    collection_page: "plp",
    category_pages: "plp",
    product_listing: "plp",
    product_page: "pdp",
    product_pages: "pdp",
    product_detail: "pdp",
    product_pdp: "pdp",
    cart: "cart",
    checkout: "checkout",
    promo: "promo",
    brand: "brand",
    brand_tone: "brand",
    navigation: "navigation",
    search: "search",
    filters: "filter",
    filter: "filter",
    browse_to_pdp: "navigation",
    pdp_to_cart: "cart",
    cart_to_checkout: "checkout",
    purchase_flow: "checkout",
    onboarding: "navigation",
    art_direction: "brand",
    premium_tone: "brand",
    interaction_reference: "navigation",
    visual_style: "brand",
    layout_reference: "homepage",
    platform_examples: "homepage",
    tech_stack_examples: "brand",
    ui_shot: "brand",
