function buildDesignReferenceSourceSeedContext(pageId = "", options = {}) {
  const pageType = classifyPageTypeForDesignRefs(pageId, options.pageGroup || "");
  const tagMap = {
    home: ["homepage", "promo", "brand", "navigation"],
    plp: ["plp", "navigation", "search", "filter", "promo"],
    pdp: ["pdp", "brand", "promo", "navigation"],
    support: ["navigation", "search", "brand"],
    bestshop: ["homepage", "brand", "navigation"],
    "care-solution": ["homepage", "pdp", "promo", "brand", "navigation"],
    generic: ["homepage", "brand", "navigation"],
  };
  const targetTags = tagMap[pageType] || tagMap.generic;
  const payload = readDesignReferenceSourceSeeds();
  const entries = (payload.entries || [])
    .map((entry) => {
      const tags = normalizeReferenceCollectTags(entry?.collectFor);
      let score = 0;
      if (tags.some((tag) => targetTags.includes(tag))) score += 100;
      if (String(entry?.sampleClass || "") === "practical") score += 40;
      else if (String(entry?.sampleClass || "") === "showcase") score += 20;
      else if (String(entry?.sampleClass || "") === "concept-shot") score -= 10;
      score += Math.max(0, 10 - Number(entry?.priority || 10));
      return {
        id: String(entry?.id || "").trim(),
        name: String(entry?.name || "").trim(),
        url: String(entry?.url || "").trim(),
        bucket: String(entry?.bucket || "").trim(),
        sampleClass: String(entry?.sampleClass || "").trim() || "showcase",
        priority: Number(entry?.priority || 99),
        role: String(entry?.role || "").trim(),
        note: String(entry?.note || "").trim(),
        collectFor: Array.isArray(entry?.collectFor) ? entry.collectFor.map((item) => String(item || "").trim()).filter(Boolean) : [],
        normalizedTags: tags,
        score,
      };
    })
    .filter((entry) => entry.id && entry.url && entry.score > 0)
    .sort((a, b) => a.priority - b.priority || b.score - a.score || a.name.localeCompare(b.name, "en"));
  return {
    generatedAt: payload.generatedAt || null,
    pageType,
    targetTags,
    count: entries.length,
    entries,
  };
}

function classifyPageTypeForDesignRefs(pageId = "", pageGroup = "") {
  const normalizedPageId = String(pageId || "").trim();
  const normalizedPageGroup = String(pageGroup || "").trim();
  if (normalizedPageId === "home" || normalizedPageId === "homestyle-home" || normalizedPageGroup === "home") return "home";
  if (normalizedPageId.startsWith("category-") || normalizedPageGroup === "category") return "plp";
  if (isPdpCasePageId(normalizedPageId) || normalizedPageId === "homestyle-pdp" || normalizedPageGroup === "product-detail") return "pdp";
  if (normalizedPageId === "support") return "support";
  if (normalizedPageId === "bestshop") return "bestshop";
  if (normalizedPageId === "care-solutions" || normalizedPageId === "care-solutions-pdp" || normalizedPageGroup === "care-solution") return "care-solution";
  if (normalizedPageId.startsWith("homestyle-") || normalizedPageGroup === "homestyle") return "generic";
  return "generic";
}

function extractIdentitySignalsFromText(value = "") {
  const text = String(value || "").toLowerCase();
  const signals = new Set();
  const tests = [
    ["premium", /(premium|luxury|high-end|warm-premium|프리미엄|고급|하이엔드)/i],
    ["trust", /(trust|reliable|assurance|enterprise|structured|documentation|신뢰|안심|전문|서비스|지원|care)/i],
    ["editorial", /(editorial|story|brand-story|cinematic|감성|스토리|매거진|브랜드\s*스토리|에디토리얼)/i],
    ["utility", /(utility|productivity|documentation-friendly|검색|필터|예약|실용|정돈|utility-layout|utility-navigation)/i],
    ["conversion", /(conversion|cta|benefit|purchase|buy|shop|상담|구매|혜택|신청|전환)/i],
    ["calm", /(calm|quiet|soft|절제|차분|정제|soft-contrast|calm-dark)/i],
    ["dense", /(dense|data-rich|grid|calendar-like-density|정보\s*밀도|촘촘)/i],
    ["minimal", /(minimal|clean-grid|monochrome|simple-hero|간결|미니멀|절제된)/i],
    ["bold", /(bold|hero-led|high-contrast|strong|임팩트|강한|대형\s*타이포)/i],
  ];
  tests.forEach(([signal, pattern]) => {
    if (pattern.test(text)) signals.add(signal);
  });
  return Array.from(signals);
}

function extractPageIdentitySignals(pageIdentity = {}) {
  const source = pageIdentity && typeof pageIdentity === "object" ? pageIdentity : {};
  const text = [
    source.role,
    source.purpose,
    source.designIntent,
    ...(Array.isArray(source.mustPreserve) ? source.mustPreserve : []),
    ...(Array.isArray(source.shouldAvoid) ? source.shouldAvoid : []),
    ...(Array.isArray(source.visualGuardrails) ? source.visualGuardrails : []),
  ].filter(Boolean).join("\n");
  return extractIdentitySignalsFromText(text);
}

function extractReferenceIdentitySignals(entry = {}) {
  const source = entry && typeof entry === "object" ? entry : {};
  const text = [
    ...(Array.isArray(source.styleSignals) ? source.styleSignals : []),
    ...(Array.isArray(source.recommendedFor) ? source.recommendedFor : []),
    ...(Array.isArray(source.usageNotes) ? source.usageNotes : []),
    ...(Array.isArray(source.collectFor) ? source.collectFor : []),
  ].filter(Boolean).join("\n");
  return extractIdentitySignalsFromText(text);
}

function inferReferenceSourceClass(entry = {}, options = {}) {
  const source = entry && typeof entry === "object" ? entry : {};
  const referenceType = String(source.referenceType || "").trim();
  const bucket = String(source.bucket || "").trim();
  const tags = normalizeReferenceCollectTags(source.collectFor || source.tags || source.recommendedFor || []);
  const recommendedFor = Array.isArray(source.recommendedFor) ? source.recommendedFor.map((item) => String(item || "").trim()).filter(Boolean) : [];
  const interventionLayer = normalizeInterventionLayer(options.interventionLayer, "page");
  if (referenceType === "design-md" || bucket === "design_md" || bucket === "design-md") return "system-reference";
  if (tags.some((tag) => ["checkout", "onboarding", "search", "filter", "cart"].includes(tag))) return "flow-pattern";
  if (interventionLayer === "component" || interventionLayer === "element") return "component-pattern";
  if (recommendedFor.some((item) => ["hero", "cta", "banner", "navigation", "card", "quickmenu", "ranking"].includes(item))) {
    return interventionLayer === "page" ? "page-mood" : "component-pattern";
  }
  return interventionLayer === "page" ? "page-mood" : "component-pattern";
}

function buildReferenceAvoidNotes(sourceClass = "", pageType = "") {
  const notes = [];
  if (sourceClass === "page-mood") {
    notes.push("exact layout copy 금지");
    notes.push("서비스 정보 구조를 그대로 복제하지 않는다");
  }
  if (sourceClass === "component-pattern") {
    notes.push("컴포넌트 외부 페이지 구조까지 따라가지 않는다");
    notes.push("현재 페이지 정체성과 맞지 않는 과한 장식은 제외한다");
  }
  if (sourceClass === "flow-pattern") {
    notes.push("모바일 앱 플로우를 데스크톱 레이아웃에 그대로 이식하지 않는다");
  }
  if (sourceClass === "system-reference") {
    notes.push("디자인 언어 참고용이며 카피/레이아웃 직접 복제 금지");
  }
  if (pageType === "home") {
    notes.push("브랜드 홈을 쇼케이스 랜딩처럼 과장하지 않는다");
  }
  return Array.from(new Set(notes));
}

function buildDesignReferenceAnchors(entries = [], options = {}) {
  const sourceSeedEntries = buildDesignReferenceSourceSeedContext(options.pageId || "", options).entries || [];
  const sourceSeedMap = new Map(sourceSeedEntries.map((item) => [String(item.url || "").trim(), item]));
  const targetComponents = Array.isArray(options.targetComponents) ? options.targetComponents.map((item) => String(item || "").trim()).filter(Boolean) : [];
  const interventionLayer = normalizeInterventionLayer(options.interventionLayer, "page");
  const viewportProfile = String(options.viewportProfile || "pc").trim() || "pc";
  const pageId = String(options.pageId || "").trim();
  const pageType = classifyPageTypeForDesignRefs(pageId, options.pageGroup || "");
  const curatedEntryAnchors = (Array.isArray(entries) ? entries : [])
    .map((entry, index) => {
      const normalizedUrl = String(entry?.url || "").trim();
      const seed = sourceSeedMap.get(normalizedUrl) || null;
      const sourceClass = inferReferenceSourceClass({
        ...seed,
        ...entry,
        collectFor: seed?.collectFor || entry?.tags || [],
      }, { interventionLayer });
      const sampleUrls = Array.isArray(entry?.sampleUrls) ? entry.sampleUrls.map((item) => String(item || "").trim()).filter(Boolean) : [];
      return {
        id: String(entry?.id || seed?.id || `reference-${index + 1}`).trim(),
        label: String(entry?.title || seed?.name || entry?.provider || entry?.id || `Reference ${index + 1}`).trim(),
        sourceUrl: normalizedUrl,
        sourceName: String(seed?.name || entry?.provider || "reference").trim(),
        sourceClass,
        targetLayer: interventionLayer,
        targetPageIds: pageId ? [pageId] : [],
        targetComponents: interventionLayer === "page" ? [] : targetComponents,
        targetGroupId: String(options.targetGroupId || "").trim(),
        viewportProfile,
        intentTags: uniqueNonEmptyLines([
          ...(Array.isArray(entry?.styleSignals) ? entry.styleSignals : []),
          ...(Array.isArray(entry?.recommendedFor) ? entry.recommendedFor : []),
          ...(Array.isArray(seed?.collectFor) ? seed.collectFor : []),
        ]).slice(0, 8),
        why: uniqueNonEmptyLines([
          ...(Array.isArray(entry?.usageNotes) ? entry.usageNotes : []),
          String(seed?.role || "").trim(),
          String(seed?.note || "").trim(),
        ]).slice(0, 4),
        avoid: buildReferenceAvoidNotes(sourceClass, pageType).slice(0, 4),
        captureMode: sampleUrls.length ? "screenshot" : "url-only",
        priority: index === 0 ? "high" : index === 1 ? "medium" : "low",
        screenshotUrls: sampleUrls.slice(0, 3),
        referenceType: String(entry?.referenceType || "").trim() || null,
      };
    });
  const seedAnchors = sourceSeedEntries.map((seed, index) => {
    const sourceClass = inferReferenceSourceClass(seed, { interventionLayer });
    return {
      id: String(seed?.id || `seed-reference-${index + 1}`).trim(),
      label: String(seed?.name || `Seed reference ${index + 1}`).trim(),
      sourceUrl: String(seed?.url || "").trim(),
      sourceName: String(seed?.name || "reference").trim(),
      sourceClass,
      targetLayer: interventionLayer,
      targetPageIds: pageId ? [pageId] : [],
      targetComponents: interventionLayer === "page" ? [] : targetComponents,
      targetGroupId: String(options.targetGroupId || "").trim(),
      viewportProfile,
      intentTags: uniqueNonEmptyLines([
        ...(Array.isArray(seed?.normalizedTags) ? seed.normalizedTags : []),
        String(seed?.bucket || "").trim(),
      ]).slice(0, 8),
      why: uniqueNonEmptyLines([
        String(seed?.role || "").trim(),
        String(seed?.note || "").trim(),
      ]).slice(0, 4),
      avoid: buildReferenceAvoidNotes(sourceClass, pageType).slice(0, 4),
      captureMode: String(seed?.url || "").trim() ? "screenshot" : "url-only",
      priority: index === 0 ? "high" : index === 1 ? "medium" : "low",
      screenshotUrls: String(seed?.url || "").trim() ? [String(seed.url || "").trim()] : [],
      referenceType: "source-seed",
    };
  });
  return [...curatedEntryAnchors, ...seedAnchors]
    .filter((item) => item?.id && item?.sourceUrl)
    .filter((item, index, list) => list.findIndex((candidate) => String(candidate?.id || "").trim() === String(item?.id || "").trim()) === index)
    .slice(0, Math.max(1, Math.min(Number(options.limit || 4) || 4, 8)));
}

function isProbablyImageUrl(rawUrl = "") {
  const source = String(rawUrl || "").trim().toLowerCase();
  if (!source) return false;
  return /\.(png|jpe?g|webp|gif|svg)(?:[?#].*)?$/.test(source);
}

async function captureReferenceAssetDataUrl(referenceUrl = "", viewportProfile = "pc") {
  const source = String(referenceUrl || "").trim();
  if (!source) return null;
  const rawDataUrl = isProbablyImageUrl(source)
    ? await fetchImageAsDataUrl(source).catch(() => null)
    : await captureUrlAsScreenshotDataUrl(source, viewportProfile).catch(() => null);
  if (!rawDataUrl) return null;
  return normalizeDataUrlForVisionInput(rawDataUrl, {
    maxWidth: 1200,
    maxHeight: 1200,
    format: "jpeg",
  }).catch(() => rawDataUrl);
}

function pickBuildReferenceAnchors(builderInput = {}, limit = 2) {
  const anchors = Array.isArray(builderInput?.systemContext?.designReferenceLibrary?.referenceAnchors)
    ? builderInput.systemContext.designReferenceLibrary.referenceAnchors
    : [];
  if (!anchors.length) return [];
  const targetComponents = new Set(toStringArray(builderInput?.generationOptions?.targetComponents));
  const interventionLayer = String(builderInput?.generationOptions?.interventionLayer || "").trim();
  return anchors
    .map((anchor, index) => {
      const anchorTargets = Array.isArray(anchor?.targetComponents) ? anchor.targetComponents.map((item) => String(item || "").trim()) : [];
      let score = 0;
      if (anchor?.captureMode === "screenshot") score += 20;
      if (String(anchor?.targetLayer || "").trim() === interventionLayer) score += 15;
      if (anchorTargets.some((item) => targetComponents.has(item))) score += 35;
      if (String(anchor?.priority || "").trim() === "high") score += 20;
      else if (String(anchor?.priority || "").trim() === "medium") score += 10;
      if (String(anchor?.sourceClass || "").trim() === "component-pattern") score += 15;
      if (String(anchor?.sourceClass || "").trim() === "page-mood" && interventionLayer === "page") score += 10;
      return { anchor, score, index };
    })
    .sort((a, b) => b.score - a.score || a.index - b.index)
    .slice(0, Math.max(1, Math.min(Number(limit || 2) || 2, 4)))
    .map((item) => item.anchor);
}

async function materializeReferenceVisualAssets(builderInput = {}) {
  const anchors = pickBuildReferenceAnchors(builderInput, 2);
  if (!anchors.length) return [];
  const viewportProfile = String(builderInput?.pageContext?.viewportProfile || "pc").trim() || "pc";
  const assets = await Promise.all(
    anchors.map(async (anchor) => {
      const candidateUrls = toStringArray(anchor?.screenshotUrls).concat(String(anchor?.sourceUrl || "").trim()).filter(Boolean);
      const captureUrl = candidateUrls[0] || "";
      const imageDataUrl = await captureReferenceAssetDataUrl(captureUrl, viewportProfile);
      if (!imageDataUrl) return null;
      return {
        id: String(anchor?.id || "").trim(),
        label: String(anchor?.label || "").trim(),
        sourceName: String(anchor?.sourceName || "").trim(),
        sourceClass: String(anchor?.sourceClass || "").trim(),
        targetLayer: String(anchor?.targetLayer || "").trim(),
        targetComponents: toStringArray(anchor?.targetComponents).slice(0, 8),
        why: toStringArray(anchor?.why).slice(0, 4),
        avoid: toStringArray(anchor?.avoid).slice(0, 4),
        captureMode: String(anchor?.captureMode || "url-only").trim(),
        sourceUrl: String(anchor?.sourceUrl || "").trim(),
        imageDataUrl,
      };
    })
  );
  const normalizedAssets = assets.filter(Boolean);
  if (normalizedAssets.length) {
    const dims = await Promise.all(
      normalizedAssets.map(async (asset) => {
        const size = await readDataUrlDimensions(asset.imageDataUrl).catch(() => null);
        return `${asset.id}:${size ? `${size.width}x${size.height}` : "unknown"}`;
      })
    );
    console.log(`[reference-assets] builder dims=${dims.join(",")}`);
  }
  return normalizedAssets;
}

async function materializePlannerReferenceVisualAssets(plannerInput = {}) {
  const anchors = Array.isArray(plannerInput?.referenceSummary?.designReferenceLibrary?.referenceAnchors)
    ? plannerInput.referenceSummary.designReferenceLibrary.referenceAnchors
    : [];
  if (!anchors.length) return [];
  const targetComponents = new Set(toStringArray(plannerInput?.userInput?.targetComponents));
  const interventionLayer = String(plannerInput?.userInput?.interventionLayer || "").trim();
  const viewportProfile = String(plannerInput?.pageContext?.viewportProfile || "pc").trim() || "pc";
  const ranked = anchors
    .map((anchor, index) => {
      const anchorTargets = Array.isArray(anchor?.targetComponents) ? anchor.targetComponents.map((item) => String(item || "").trim()) : [];
      let score = 0;
      if (anchor?.captureMode === "screenshot") score += 20;
      if (String(anchor?.targetLayer || "").trim() === interventionLayer) score += 15;
      if (anchorTargets.some((item) => targetComponents.has(item))) score += 35;
      if (String(anchor?.priority || "").trim() === "high") score += 20;
      else if (String(anchor?.priority || "").trim() === "medium") score += 10;
      return { anchor, score, index };
    })
    .sort((a, b) => b.score - a.score || a.index - b.index)
    .slice(0, 2)
    .map((item) => item.anchor);
  const assets = await Promise.all(
    ranked.map(async (anchor) => {
      const candidateUrls = toStringArray(anchor?.screenshotUrls).concat(String(anchor?.sourceUrl || "").trim()).filter(Boolean);
      const captureUrl = candidateUrls[0] || "";
      const imageDataUrl = await captureReferenceAssetDataUrl(captureUrl, viewportProfile);
      if (!imageDataUrl) return null;
      return {
        id: String(anchor?.id || "").trim(),
        label: String(anchor?.label || "").trim(),
        sourceName: String(anchor?.sourceName || "").trim(),
        sourceClass: String(anchor?.sourceClass || "").trim(),
        targetLayer: String(anchor?.targetLayer || "").trim(),
        targetComponents: toStringArray(anchor?.targetComponents).slice(0, 8),
        why: toStringArray(anchor?.why).slice(0, 4),
        avoid: toStringArray(anchor?.avoid).slice(0, 4),
        sourceUrl: String(anchor?.sourceUrl || "").trim(),
        imageDataUrl,
      };
    })
  );
  const normalizedAssets = assets.filter(Boolean);
  if (normalizedAssets.length) {
    const dims = await Promise.all(
      normalizedAssets.map(async (asset) => {
        const size = await readDataUrlDimensions(asset.imageDataUrl).catch(() => null);
        return `${asset.id}:${size ? `${size.width}x${size.height}` : "unknown"}`;
      })
    );
    console.log(`[reference-assets] planner dims=${dims.join(",")}`);
  }
  return normalizedAssets;
}

function readWholePageContextTargetComponents(input = {}) {
  const plannerComponents = input?.userInput?.targetComponents;
  const builderComponents = input?.generationOptions?.targetComponents;
  return toStringArray(Array.isArray(builderComponents) ? builderComponents : plannerComponents).slice(0, 20);
}

function readWholePageContextTargetMetadata(input = {}) {
  const plannerTargeting = input?.pageSummary?.targeting || {};
  const builderTargeting = input?.systemContext?.targeting || {};
  const generationOptions = input?.generationOptions || {};
  const userInput = input?.userInput || {};
  return {
    interventionLayer: String(
      generationOptions?.interventionLayer ||
      userInput?.interventionLayer ||
      builderTargeting?.interventionLayer ||
      plannerTargeting?.interventionLayer ||
      "page"
    ).trim() || "page",
    targetGroupId: String(
      generationOptions?.targetGroupId ||
      userInput?.targetGroupId ||
      builderTargeting?.targetGroupId ||
      plannerTargeting?.targetGroupId ||
      ""
    ).trim(),
    targetGroupLabel: String(
      generationOptions?.targetGroupLabel ||
      userInput?.targetGroupLabel ||
      builderTargeting?.targetGroupLabel ||
      plannerTargeting?.targetGroupLabel ||
      ""
    ).trim(),
  };
}

function pickWholePageContextSectionRect(section = null) {
  const rect =
    section?.geometry?.workingRect ||
    section?.geometry?.referenceRect ||
    section?.geometry?.plannedContentRect ||
    section?.geometry?.plannedSectionRect ||
    null;
  if (!rect || typeof rect !== "object") return null;
  const width = Number(rect.width || 0);
  const height = Number(rect.height || 0);
  if (!width || !height) return null;
  return {
    x: Number(rect.x || 0),
    y: Number(rect.y || 0),
    width,
    height,
  };
}

function unionWholePageContextRects(rects = []) {
  const safeRects = safeObjectArray(rects, 30).filter((item) => Number(item?.width || 0) > 0 && Number(item?.height || 0) > 0);
  if (!safeRects.length) return null;
  const minX = Math.min(...safeRects.map((item) => Number(item.x || 0)));
  const minY = Math.min(...safeRects.map((item) => Number(item.y || 0)));
  const maxX = Math.max(...safeRects.map((item) => Number(item.x || 0) + Number(item.width || 0)));
  const maxY = Math.max(...safeRects.map((item) => Number(item.y || 0) + Number(item.height || 0)));
  return {
    x: minX,
    y: minY,
    width: Math.max(0, maxX - minX),
    height: Math.max(0, maxY - minY),
  };
}

function chooseWholePageContextRegistry(pageId, viewportProfile, editableData, input = {}, targetComponentCount = 0) {
  const inlineRegistry =
    input?.systemContext?.artifactSidecarRegistry && Array.isArray(input.systemContext.artifactSidecarRegistry.sections)
      ? input.systemContext.artifactSidecarRegistry
      : null;
  const rebuiltRegistry = buildArtifactSidecarRegistry(pageId, {
    editableData,
    viewportProfile,
  });
  const inlineCount = Array.isArray(inlineRegistry?.sections) ? inlineRegistry.sections.length : 0;
  const rebuiltCount = Array.isArray(rebuiltRegistry?.sections) ? rebuiltRegistry.sections.length : 0;
  const minimumExpected = Math.max(1, Number(targetComponentCount || 0));
  console.log(
    `[whole-page-context] registry-source page=${String(pageId || "").trim()} inlineSections=${inlineCount} rebuiltSections=${rebuiltCount} targetComponents=${minimumExpected} inlineSample=${(Array.isArray(inlineRegistry?.sections) ? inlineRegistry.sections : []).slice(0, 6).map((section) => String(section?.componentId || section?.slotId || "null")).join(",")} rebuiltSample=${(Array.isArray(rebuiltRegistry?.sections) ? rebuiltRegistry.sections : []).slice(0, 6).map((section) => String(section?.componentId || section?.slotId || "null")).join(",")}`
  );
  if (!inlineRegistry) return rebuiltRegistry;
  if (inlineCount >= rebuiltCount && inlineCount >= minimumExpected) return inlineRegistry;
  console.log(
    `[whole-page-context] registry-rebuild page=${String(pageId || "").trim()} inlineSections=${inlineCount} rebuiltSections=${rebuiltCount} targetComponents=${minimumExpected}`
  );
  return rebuiltCount ? rebuiltRegistry : inlineRegistry;
}

function buildWholePageContextSections(pageId, viewportProfile, editableData, input = {}) {
  const targetComponentIds = new Set(readWholePageContextTargetComponents(input));
  const registry = chooseWholePageContextRegistry(
    pageId,
    viewportProfile,
    editableData,
    input,
    targetComponentIds.size
  );
  const targetSlotIds = new Set(
    readWholePageContextTargetComponents(input)
      .map((item) => inferSlotIdFromComponentId(item) || String(item || "").trim())
      .filter(Boolean)
  );
  toStringArray(input?.approvedPlan?.builderBrief?.suggestedFocusSlots).forEach((item) => targetSlotIds.add(String(item || "").trim()));
  toStringArray(input?.pageSummary?.editableSlots).forEach((item) => targetSlotIds.add(String(item || "").trim()));
  const allSections = safeObjectArray(registry?.sections || [], 100);
  const targetMeta = readWholePageContextTargetMetadata(input);
  const normalizedPageId = String(pageId || "").trim();
  const isPageLayer = targetMeta.interventionLayer === "page";
  let sections = allSections;
  if (!isPageLayer && targetComponentIds.size) {
    sections = sections.filter((section) => targetComponentIds.has(String(section?.componentId || "").trim()));
  }
  if (!isPageLayer && !sections.length && targetSlotIds.size) {
    sections = allSections.filter((section) => targetSlotIds.has(String(section?.slotId || "").trim()));
  }
  if (!sections.length && targetMeta.targetGroupId) {
    const fallbackSpec = resolveInterventionRequest(normalizedPageId, editableData, {
      viewportProfile,
      interventionLayer: targetMeta.interventionLayer,
      patchDepth: "medium",
      targetGroupId: targetMeta.targetGroupId,
    });
    const fallbackSet = new Set(toStringArray(fallbackSpec?.targetComponents).slice(0, 50));
    if (fallbackSet.size) {
      sections = allSections.filter((section) =>
        fallbackSet.has(String(section?.componentId || "").trim()) ||
        fallbackSet.has(String(section?.slotId || "").trim())
      );
    }
  }
  if (!sections.length && !isPageLayer && targetSlotIds.size) {
    sections = allSections.filter((section) => targetSlotIds.has(String(section?.slotId || "").trim()));
  }
  console.log(
    `[whole-page-context] match page=${normalizedPageId} registrySections=${allSections.length} targetComponents=${Array.from(targetComponentIds).join(",") || "none"} targetSlots=${Array.from(targetSlotIds).join(",") || "none"} matchedSections=${sections.length}`
  );
  return sections
    .map((section) => {
      const rect = pickWholePageContextSectionRect(section);
      if (!rect) return null;
      return {
        componentId: String(section?.componentId || "").trim(),
        slotId: String(section?.slotId || "").trim(),
        label: String(section?.label || section?.slotId || section?.componentId || "").trim(),
        rect,
      };
    })
    .filter(Boolean)
    .slice(0, 20);
}

async function buildWholePageContextOverlayDataUrl(baseImageDataUrl = "", sections = [], metadata = {}) {
  const decoded = decodeDataUrlToBuffer(baseImageDataUrl);
  if (!decoded?.buffer) return null;
  const image = sharp(decoded.buffer);
  const imageMeta = await image.metadata();
  const width = Math.max(1, Number(imageMeta.width || 0));
  const height = Math.max(1, Number(imageMeta.height || 0));
  if (!width || !height) return null;
  const rects = safeObjectArray(sections, 20).map((item) => item?.rect).filter(Boolean);
  const unionRect = unionWholePageContextRects(rects);
  const targetLabel = String(metadata?.targetLabel || "").trim() || "Target region";
  const sectionLines = safeArray(
    safeObjectArray(sections, 4).map((item) => String(item?.label || item?.slotId || item?.componentId || "").trim()).filter(Boolean),
    4
  );
  const titleX = unionRect ? Math.max(32, Math.min(width - 440, unionRect.x + 18)) : 32;
  const titleY = unionRect ? Math.max(56, unionRect.y - 64) : 56;
  const cardX = unionRect ? Math.max(16, Math.min(width - 456, unionRect.x)) : 16;
  const cardY = unionRect ? Math.max(16, unionRect.y - 104) : 16;
  const cardHeight = 64 + sectionLines.length * 22;
  const svg = [
    `<svg width="${width}" height="${height}" viewBox="0 0 ${width} ${height}" xmlns="http://www.w3.org/2000/svg">`,
    `<rect x="0" y="0" width="${width}" height="${height}" fill="rgba(5, 12, 20, 0.18)"/>`,
    ...safeObjectArray(sections, 20).map((item) => {
      const rect = item?.rect;
      if (!rect) return "";
      return `<rect x="${rect.x}" y="${rect.y}" width="${rect.width}" height="${rect.height}" rx="18" fill="rgba(37, 99, 235, 0.16)" stroke="rgba(37, 99, 235, 0.92)" stroke-width="6"/>`;
    }),
    unionRect
      ? `<rect x="${unionRect.x}" y="${unionRect.y}" width="${unionRect.width}" height="${unionRect.height}" rx="22" fill="none" stroke="rgba(245, 158, 11, 0.96)" stroke-width="8" stroke-dasharray="18 14"/>`
      : "",
    `<rect x="${cardX}" y="${cardY}" width="440" height="${cardHeight}" rx="18" fill="rgba(15, 23, 42, 0.92)"/>`,
    `<text x="${titleX}" y="${titleY}" fill="#ffffff" font-size="28" font-family="Arial, sans-serif" font-weight="700">${escapeHtml(targetLabel)}</text>`,
    ...sectionLines.map((line, index) => {
      const textY = titleY + 30 + index * 22;
      return `<text x="${titleX}" y="${textY}" fill="rgba(226,232,240,0.96)" font-size="18" font-family="Arial, sans-serif">${escapeHtml(line)}</text>`;
    }),
    `</svg>`,
  ].filter(Boolean).join("");
  const composed = await image
    .composite([{ input: Buffer.from(svg), top: 0, left: 0 }])
    .png()
    .toBuffer();
  return `data:image/png;base64,${composed.toString("base64")}`;
}

async function buildWholePageContextFocusDataUrl(baseImageDataUrl = "", sections = []) {
  const decoded = decodeDataUrlToBuffer(baseImageDataUrl);
  if (!decoded?.buffer) return null;
  const image = sharp(decoded.buffer);
  const imageMeta = await image.metadata();
  const imageWidth = Math.max(1, Number(imageMeta.width || 0));
  const imageHeight = Math.max(1, Number(imageMeta.height || 0));
  if (!imageWidth || !imageHeight) return null;
  const unionRect = unionWholePageContextRects(
    safeObjectArray(sections, 20).map((item) => item?.rect).filter(Boolean)
  );
  if (!unionRect) return null;
  const paddingX = Math.max(32, Math.round(unionRect.width * 0.12));
  const paddingY = Math.max(32, Math.round(unionRect.height * 0.18));
  const left = Math.max(0, Math.floor(unionRect.x - paddingX));
  const top = Math.max(0, Math.floor(unionRect.y - paddingY));
  const width = Math.min(imageWidth - left, Math.ceil(unionRect.width + paddingX * 2));
  const height = Math.min(imageHeight - top, Math.ceil(unionRect.height + paddingY * 2));
  if (width <= 0 || height <= 0) return null;
  try {
    const cropped = await image.extract({ left, top, width, height }).png().toBuffer();
    return `data:image/png;base64,${cropped.toString("base64")}`;
  } catch (error) {
    console.warn(
      `[whole-page-context] focus-crop-failed left=${left} top=${top} width=${width} height=${height} reason=${String(error)}`
    );
    return null;
  }
}

async function buildWholePageFallbackSectionsFromImage(pageId = "", input = {}, baseImageDataUrl = "") {
  const decoded = decodeDataUrlToBuffer(baseImageDataUrl);
  if (!decoded?.buffer) return [];
  const image = sharp(decoded.buffer);
  const meta = await image.metadata();
  const width = Math.max(1, Number(meta.width || 0));
  const height = Math.max(1, Number(meta.height || 0));
  if (!width || !height) return [];
  const slotIds = Array.from(
    new Set(
      readWholePageContextTargetComponents(input)
        .map((item) => inferSlotIdFromComponentId(item) || String(item || "").trim())
        .concat(toStringArray(input?.approvedPlan?.builderBrief?.suggestedFocusSlots))
        .concat(toStringArray(input?.pageSummary?.editableSlots))
        .filter(Boolean)
    )
  );
  if (!slotIds.length) return [];
  const normalizedPageId = String(pageId || "").trim();
  if (normalizedPageId === "home") {
    const sectionMap = {
      "header-top": { x: width * 0.02, y: height * 0.01, width: width * 0.96, height: Math.max(90, height * 0.035) },
      "header-bottom": { x: width * 0.02, y: height * 0.045, width: width * 0.96, height: Math.max(100, height * 0.04) },
      hero: { x: width * 0.02, y: height * 0.085, width: width * 0.96, height: Math.max(920, height * 0.24) },
      quickmenu: { x: width * 0.08, y: height * 0.31, width: width * 0.84, height: Math.max(280, height * 0.08) },
      "md-choice": { x: width * 0.06, y: height * 0.40, width: width * 0.88, height: Math.max(420, height * 0.10) },
      timedeal: { x: width * 0.06, y: height * 0.52, width: width * 0.88, height: Math.max(420, height * 0.10) },
      "best-ranking": { x: width * 0.06, y: height * 0.63, width: width * 0.88, height: Math.max(420, height * 0.10) },
    };
    const sections = slotIds
      .map((slotId) => {
        const rect = sectionMap[slotId];
        if (!rect) return null;
        return {
          componentId: `home.${slotId}`,
          slotId,
          label: slotId,
          rect: {
            x: Math.round(rect.x),
            y: Math.round(rect.y),
            width: Math.round(rect.width),
            height: Math.round(rect.height),
          },
        };
      })
      .filter(Boolean);
    if (sections.length) return sections;
  }
  if (normalizedPageId === "homestyle-home") {
    const sectionMap = {
      quickMenu: { x: width * 0.06, y: height * 0.10, width: width * 0.88, height: Math.max(280, height * 0.12) },
      labelBanner: { x: width * 0.06, y: height * 0.27, width: width * 0.88, height: Math.max(360, height * 0.16) },
      brandStory: { x: width * 0.06, y: height * 0.48, width: width * 0.88, height: Math.max(520, height * 0.22) },
      hero: { x: width * 0.04, y: height * 0.04, width: width * 0.92, height: Math.max(560, height * 0.20) },
    };
    const sections = slotIds
      .map((slotId) => {
        const rect = sectionMap[slotId];
        if (!rect) return null;
        return {
          componentId: `homestyle-home.${slotId}`,
          slotId,
          label: slotId,
          rect: {
            x: Math.round(rect.x),
            y: Math.round(rect.y),
            width: Math.round(rect.width),
            height: Math.round(rect.height),
          },
        };
      })
      .filter(Boolean);
    if (sections.length) return sections;
  }
  if (normalizedPageId === "care-solutions") {
    const sectionMap = {
      hero: { x: width * 0.04, y: height * 0.05, width: width * 0.92, height: Math.max(600, height * 0.22) },
      tabs: { x: width * 0.10, y: height * 0.29, width: width * 0.80, height: Math.max(180, height * 0.07) },
      ranking: { x: width * 0.06, y: height * 0.39, width: width * 0.88, height: Math.max(420, height * 0.14) },
      benefit: { x: width * 0.06, y: height * 0.56, width: width * 0.88, height: Math.max(420, height * 0.14) },
      careBanner: { x: width * 0.08, y: height * 0.74, width: width * 0.84, height: Math.max(280, height * 0.10) },
    };
    const sections = slotIds
      .map((slotId) => {
        const rect = sectionMap[slotId];
        if (!rect) return null;
        return {
          componentId: `care-solutions.${slotId}`,
          slotId,
          label: slotId,
          rect: {
            x: Math.round(rect.x),
            y: Math.round(rect.y),
            width: Math.round(rect.width),
            height: Math.round(rect.height),
          },
        };
      })
      .filter(Boolean);
    if (sections.length) return sections;
  }
  const bandHeight = Math.max(320, Math.round(height * 0.18));
  const inferredBand =
    slotIds.some((slotId) => /header|hero|quickmenu|top/i.test(slotId))
      ? { x: Math.round(width * 0.04), y: Math.round(height * 0.06), width: Math.round(width * 0.92), height: bandHeight }
      : slotIds.some((slotId) => /middle|ranking|product|grid|list|card|banner/i.test(slotId))
        ? { x: Math.round(width * 0.05), y: Math.round(height * 0.36), width: Math.round(width * 0.90), height: bandHeight }
        : { x: Math.round(width * 0.05), y: Math.round(height * 0.62), width: Math.round(width * 0.90), height: bandHeight };
  return [{
    componentId: `${normalizedPageId}.focus-band`,
    slotId: "focus-band",
    label: "focus-band",
    rect: inferredBand,
  }];
}

async function materializeCloneTargetReferenceAssets(input = {}, options = {}) {
  const pageId = String(options.pageId || input?.pageContext?.workspacePageId || "").trim();
  const viewportProfile = String(options.viewportProfile || input?.pageContext?.viewportProfile || "pc").trim() || "pc";
  const userId = String(options.userId || "").trim();
  if (!pageId || !userId) return [];
  const baseUrl = buildInternalVisualCriticPreviewUrl(pageId, {
    userId,
    viewportProfile,
  });
  const fallbackCloneUrl = `http://127.0.0.1:${PORT}/clone/${encodeURIComponent(pageId)}?viewportProfile=${encodeURIComponent(viewportProfile)}`;
  let rawFullPageImageDataUrl = await captureUrlAsScreenshotDataUrl(baseUrl, viewportProfile, { fullPage: true }).catch(() => null);
  if (!rawFullPageImageDataUrl) {
    rawFullPageImageDataUrl = await captureUrlAsScreenshotDataUrl(fallbackCloneUrl, viewportProfile, { fullPage: true }).catch(() => null);
  }
  const fullPageImageDataUrl = rawFullPageImageDataUrl
    ? await normalizeWholePageDataUrlForVisionInput(rawFullPageImageDataUrl, {
        targetWidth: 1400,
        minimumWidth: 1000,
        baseMaxHeight: 4200,
        hardMaxHeight: 7200,
        quality: 80,
      }).catch(() => rawFullPageImageDataUrl)
    : null;
  if (!fullPageImageDataUrl) return [];
  let sections = buildWholePageContextSections(pageId, viewportProfile, options.editableData, input);
  if (!sections.length) {
    sections = await buildWholePageFallbackSectionsFromImage(pageId, input, fullPageImageDataUrl).catch(() => []);
  }
  const pickedSections = safeObjectArray(sections, 4).slice(0, 3);
  const assets = [];
  for (const section of pickedSections) {
    const focusImageDataUrl = await buildWholePageContextFocusDataUrl(fullPageImageDataUrl, [section]).catch(() => null);
    const normalizedImageDataUrl = focusImageDataUrl
      ? await normalizeDataUrlForVisionInput(focusImageDataUrl, {
          maxWidth: 1200,
          maxHeight: 1200,
          format: "jpeg",
        }).catch(() => focusImageDataUrl)
      : null;
    if (!normalizedImageDataUrl) continue;
    const slotId = String(section?.slotId || "").trim();
    const componentId = String(section?.componentId || "").trim();
    assets.push({
      id: `clone-reference-${slotId || assets.length + 1}`,
      label: `${String(section?.label || slotId || componentId || "section").trim()} reference crop`,
      sourceName: "clone-target-reference",
      sourceClass: "system-reference",
      targetLayer: normalizeInterventionLayer(input?.generationOptions?.interventionLayer, "page"),
      targetComponents: [componentId, slotId].filter(Boolean),
      why: ["Use this original clone crop as local component reference before changing structure or assets."],
      avoid: ["Do not overfit local styling if it breaks full-page hierarchy."],
      sourceUrl: baseUrl,
      imageDataUrl: normalizedImageDataUrl,
    });
  }
  return assets;
}

async function materializeWholePageContextVisualAssets(input = {}, options = {}) {
  const pageId = String(options.pageId || input?.pageContext?.workspacePageId || "").trim();
  const viewportProfile = String(options.viewportProfile || input?.pageContext?.viewportProfile || "pc").trim() || "pc";
  const userId = String(options.userId || "").trim();
  if (!pageId || !userId) return [];
  const baseUrl = buildInternalVisualCriticPreviewUrl(pageId, {
    userId,
    viewportProfile,
  });
  const fallbackCloneUrl = `http://127.0.0.1:${PORT}/clone/${encodeURIComponent(pageId)}?viewportProfile=${encodeURIComponent(viewportProfile)}`;
  let rawFullPageImageDataUrl = await captureUrlAsScreenshotDataUrl(baseUrl, viewportProfile, { fullPage: true }).catch((error) => {
    console.warn(`[whole-page-context] capture-failed page=${pageId} source=internal-preview reason=${String(error?.message || error || "")}`);
    return null;
  });
  if (!rawFullPageImageDataUrl) {
    rawFullPageImageDataUrl = await captureUrlAsScreenshotDataUrl(fallbackCloneUrl, viewportProfile, { fullPage: true }).catch((error) => {
      console.warn(`[whole-page-context] capture-failed page=${pageId} source=public-clone reason=${String(error?.message || error || "")}`);
      return null;
    });
  }
  const fullPageImageDataUrl = rawFullPageImageDataUrl
    ? await normalizeWholePageDataUrlForVisionInput(rawFullPageImageDataUrl, {
        targetWidth: 1400,
        minimumWidth: 1000,
        baseMaxHeight: 4200,
        hardMaxHeight: 7200,
        quality: 80,
      }).catch(() => rawFullPageImageDataUrl)
    : null;
  if (!fullPageImageDataUrl) return [];
  let sections = buildWholePageContextSections(pageId, viewportProfile, options.editableData, input);
  if (!sections.length) {
    sections = await buildWholePageFallbackSectionsFromImage(pageId, input, fullPageImageDataUrl).catch(() => []);
    if (sections.length) {
      console.log(`[whole-page-context] fallback page=${pageId} sections=${sections.length}`);
    }
  }
  const targetMeta = readWholePageContextTargetMetadata(input);
  const targetLabel =
    targetMeta.targetGroupLabel ||
    (targetMeta.interventionLayer === "page" ? "Whole page context" : "Target region");
  console.log(
    `[whole-page-context] prepare page=${pageId} viewport=${viewportProfile} layer=${targetMeta.interventionLayer} targetGroup=${targetMeta.targetGroupId || "none"} targetComponents=${readWholePageContextTargetComponents(input).length} sections=${sections.length}`
  );
  const rawOverlayImageDataUrl = sections.length
    ? await buildWholePageContextOverlayDataUrl(fullPageImageDataUrl, sections, { targetLabel }).catch(() => null)
    : null;
  const overlayImageDataUrl = rawOverlayImageDataUrl
    ? await normalizeWholePageDataUrlForVisionInput(rawOverlayImageDataUrl, {
        targetWidth: 1400,
        minimumWidth: 1000,
        baseMaxHeight: 4200,
        hardMaxHeight: 7200,
        quality: 80,
      }).catch(() => rawOverlayImageDataUrl)
    : null;
  const rawDirectFocusImageDataUrl = sections.length
    ? await buildWholePageContextFocusDataUrl(fullPageImageDataUrl, sections).catch(() => null)
    : null;
  const directFocusImageDataUrl = rawDirectFocusImageDataUrl
    ? await normalizeDataUrlForVisionInput(rawDirectFocusImageDataUrl, {
        maxWidth: 1200,
        maxHeight: 1200,
        format: "jpeg",
      }).catch(() => rawDirectFocusImageDataUrl)
    : null;
  const rawOverlayFocusImageDataUrl =
    !directFocusImageDataUrl && overlayImageDataUrl
      ? await buildWholePageContextFocusDataUrl(overlayImageDataUrl, sections).catch(() => null)
      : null;
  const overlayFocusImageDataUrl = rawOverlayFocusImageDataUrl
    ? await normalizeDataUrlForVisionInput(rawOverlayFocusImageDataUrl, {
        maxWidth: 1200,
        maxHeight: 1200,
        format: "jpeg",
      }).catch(() => rawOverlayFocusImageDataUrl)
    : null;
  const focusImageDataUrl = directFocusImageDataUrl || overlayFocusImageDataUrl || overlayImageDataUrl || null;
  const targetComponents = readWholePageContextTargetComponents(input);
  const assets = [
    {
      id: "clone-original-fullpage",
      label: "Original full-page clone",
      sourceName: "clone-original",
      sourceClass: "system-reference",
      targetLayer: targetMeta.interventionLayer,
      targetComponents,
      why: ["Use the whole page first so hierarchy, rhythm, and surrounding sections stay coherent."],
      avoid: ["Do not redesign the target region in isolation from the full page."],
      sourceUrl: baseUrl,
      imageDataUrl: fullPageImageDataUrl,
    },
    overlayImageDataUrl
      ? {
          id: "clone-target-overlay",
          label: "Target-region overlay",
          sourceName: "clone-target-overlay",
          sourceClass: "system-reference",
          targetLayer: targetMeta.interventionLayer,
          targetComponents,
          why: ["The highlighted area is the exact scope that may move inside the original clone."],
          avoid: ["Do not let the target break the page rhythm around it."],
          sourceUrl: baseUrl,
          imageDataUrl: overlayImageDataUrl,
        }
      : null,
    focusImageDataUrl
      ? {
          id: "clone-target-focus",
          label: "Target focus crop",
          sourceName: "clone-target-focus",
          sourceClass: "system-reference",
          targetLayer: targetMeta.interventionLayer,
          targetComponents,
          why: ["Inspect local detail only after checking the full-page composition."],
          avoid: ["Do not over-optimize the crop against the full-page hierarchy."],
          sourceUrl: baseUrl,
          imageDataUrl: focusImageDataUrl,
        }
      : null,
  ].filter(Boolean).slice(0, 3);
  const dimensionSummary = await Promise.all(
    assets.map(async (asset) => {
      const size = await readDataUrlDimensions(asset.imageDataUrl).catch(() => null);
      return `${asset.id}:${size ? `${size.width}x${size.height}` : "unknown"}`;
    })
  );
  const narrowAssets = await Promise.all(
    assets.map(async (asset) => {
      const size = await readDataUrlDimensions(asset.imageDataUrl).catch(() => null);
      if (!size || size.width >= 1000) return null;
      return `${asset.id}:${size.width}x${size.height}`;
    })
  );
  const narrowAssetSummary = narrowAssets.filter(Boolean);
  console.log(
    `[whole-page-context] assets page=${pageId} full=${fullPageImageDataUrl ? "yes" : "no"} overlay=${overlayImageDataUrl ? "yes" : "no"} focus=${focusImageDataUrl ? "yes" : "no"} assetCount=${assets.length} dims=${dimensionSummary.join(",")}`
  );
  if (narrowAssetSummary.length) {
    console.warn(`[whole-page-context] narrow-assets page=${pageId} dims=${narrowAssetSummary.join(",")}`);
  }
  return assets;
}

function buildDesignReferenceLibraryContext(pageId = "", options = {}) {
  const pageType = classifyPageTypeForDesignRefs(pageId, options.pageGroup || "");
  const viewportProfile = String(options.viewportProfile || "pc").trim() || "pc";
  const limit = Math.max(1, Math.min(Number(options.limit || 8) || 8, 20));
  const library = readDesignReferenceLibrary();
  const identitySignals = extractPageIdentitySignals(options.pageIdentity);
  const scoredEntries = (library.entries || [])
    .map((entry) => {
      const pageTypes = Array.isArray(entry?.pageTypes) ? entry.pageTypes.map((item) => String(item || "").trim()) : [];
      const viewportProfiles = Array.isArray(entry?.viewportProfiles) ? entry.viewportProfiles.map((item) => String(item || "").trim()) : [];
      const fetchStatus = String(entry?.fetchStatus || "").trim();
      const sampleClass = String(entry?.sampleClass || "").trim();
      const referenceType = String(entry?.referenceType || "").trim();
      const sampleCount = Array.isArray(entry?.sampleUrls) ? entry.sampleUrls.length : 0;
      const referenceSignals = extractReferenceIdentitySignals(entry);
      let score = 0;
      if (pageTypes.includes(pageType)) score += 100;
      else if (pageTypes.includes("generic")) score += 30;
      if (viewportProfiles.includes(viewportProfile)) score += 30;
      else if (!viewportProfiles.length) score += 10;
      if (sampleClass === "practical") score += 40;
      else if (sampleClass === "showcase") score += 20;
      else if (sampleClass === "concept-shot") score -= 10;
      if (fetchStatus && fetchStatus !== "ok") score -= 120;
      const identityOverlap = identitySignals.filter((signal) => referenceSignals.includes(signal));
      score += identityOverlap.length * 35;
      if (identitySignals.some((signal) => ["trust", "utility", "conversion"].includes(signal)) && sampleClass === "concept-shot") {
        score -= 30;
      }
      const excluded =
        (referenceType === "practical-sample-source" && fetchStatus && fetchStatus !== "ok") ||
        (referenceType === "practical-sample-source" && sampleClass === "practical" && sampleCount <= 0);
      return { entry, score, excluded, referenceSignals, identityOverlap };
    })
    .filter((item) => item.score > 0 && !item.excluded)
    .sort((a, b) => b.score - a.score || String(a.entry?.title || "").localeCompare(String(b.entry?.title || ""), "en"));
  const entries = scoredEntries.slice(0, limit).map((item) => ({
    id: String(item.entry?.id || "").trim(),
    title: String(item.entry?.title || "").trim(),
    provider: String(item.entry?.provider || "").trim(),
    url: String(item.entry?.url || "").trim(),
    referenceType: String(item.entry?.referenceType || "design-md").trim(),
    sampleClass: String(item.entry?.sampleClass || "system-reference").trim(),
    bucket: String(item.entry?.bucket || "design_md").trim(),
    tags: normalizeReferenceCollectTags(item.entry?.collectFor || item.entry?.recommendedFor || []),
    fetchStatus: String(item.entry?.fetchStatus || "").trim() || null,
    sampleCount: Array.isArray(item.entry?.sampleUrls) ? item.entry.sampleUrls.length : 0,
    styleSignals: Array.isArray(item.entry?.styleSignals) ? item.entry.styleSignals.map((signal) => String(signal || "").trim()).filter(Boolean) : [],
    identitySignals: item.referenceSignals,
    identityOverlap: item.identityOverlap,
    recommendedFor: Array.isArray(item.entry?.recommendedFor) ? item.entry.recommendedFor.map((signal) => String(signal || "").trim()).filter(Boolean) : [],
    usageNotes: Array.isArray(item.entry?.usageNotes) ? item.entry.usageNotes.map((note) => String(note || "").trim()).filter(Boolean) : [],
    score: item.score,
  }));
  const sourceSeeds = buildDesignReferenceSourceSeedContext(pageId, options);
  const referenceAnchors = buildDesignReferenceAnchors(entries, {
    pageId,
    pageGroup: options.pageGroup,
    viewportProfile,
    interventionLayer: options.interventionLayer,
    targetComponents: options.targetComponents,
    targetGroupId: options.targetGroupId,
    limit,
  });
  return {
    generatedAt: library.generatedAt || null,
    pageType,
    viewportProfile,
    identitySignals,
    count: entries.length,
    entries,
    sourceSeeds,
    referenceAnchors,
  };
}

function readHomeVisualMetadata() {
  const metadataPath = path.join(VISUAL_DIR, "home", "metadata.json");
  if (!fs.existsSync(metadataPath)) return null;
  return readJsonFile(metadataPath);
}

function getGnbWorkbenchSourceUrls(pageId) {
  const baseline = resolveBaselineInfo(pageId);
  return {
    referenceUrl: baseline.structuralUrl || baseline.url,
    workingUrl: `http://localhost:${PORT}/clone-content/${encodeURIComponent(pageId)}`,
  };
}

function readGnbStateArtifact(rawUrl, menu) {
  const base = `${slugLoose(rawUrl)}__${slugLoose(menu)}`;
  const jsonPath = path.join(GNB_STATE_DIR, `${base}.json`);
  const defaultPngPath = path.join(GNB_STATE_DIR, `${base}.default.png`);
  const openPngPath = path.join(GNB_STATE_DIR, `${base}.open.png`);
  if (!fs.existsSync(jsonPath)) return null;
  return {
    base,
    json: readJsonFile(jsonPath),
    jsonUrl: `/debug/gnb-state/${encodeURIComponent(`${base}.json`)}`,
    defaultImageUrl: fs.existsSync(defaultPngPath)
      ? `/debug/gnb-state/${encodeURIComponent(`${base}.default.png`)}`
      : null,
    openImageUrl: fs.existsSync(openPngPath)
      ? `/debug/gnb-state/${encodeURIComponent(`${base}.open.png`)}`
      : null,
  };
}

function summarizeGnbStateArtifact(artifact) {
  const payload = artifact?.json || {};
  const before = payload.beforeSummary?.matched || null;
  const after = payload.afterSummary?.matched || null;
  const diff = payload.diff || {};
  const activeDepth2 = (after?.depth2 || []).find((item) => String(item.classes || "").includes("active")) || null;
  const visiblePanels = (after?.depth3Panels || []).filter((item) => {
    const display = item?.style?.display;
    const width = item?.rect?.width || 0;
    const height = item?.rect?.height || 0;
    return display !== "none" && width > 0 && height > 0;
  });
  return {
    url: payload.url || "",
    menu: payload.menu || "",
    hoverResult: payload.hoverResult || "unknown",
    openStateValid: payload.openStateValid !== false,
    before: before
      ? {
          ariaExpanded: before.ariaExpanded || "",
          panelRect: before.panelRect || null,
          topStripRect: before.topStripRect || null,
          panelStyle: before.panelStyle || null,
          depth2Count: (before.depth2 || []).length,
          depth3Count: (before.depth3Panels || []).length,
          depth2Labels: (before.depth2 || []).map((item) => item.label).filter(Boolean),
        }
      : null,
    after: after
      ? {
          ariaExpanded: after.ariaExpanded || "",
          navItemClasses: after.navItemClasses || "",
          panelRect: after.panelRect || null,
          topStripRect: after.topStripRect || null,
          panelStyle: after.panelStyle || null,
          depth2Count: (after.depth2 || []).length,
          depth3Count: (after.depth3Panels || []).length,
          depth2Labels: (after.depth2 || []).map((item) => item.label).filter(Boolean),
          activeDepth2Label: activeDepth2?.label || null,
          visibleDepth3Count: visiblePanels.length,
        }
      : null,
    diff: {
      panelRectAfter: diff.panel?.rectAfter || null,
      panelStyleAfter: diff.panel?.styleAfter || null,
      depth2CountAfter: diff.depth2?.countAfter ?? null,
      depth3CountAfter: diff.depth3Panels?.countAfter ?? null,
    },
  };
}

function normalizeLgeUrl(rawUrl) {
  const value = String(rawUrl || "").trim();
  if (!value) return "";
  try {
    return new URL(value, "https://www.lge.co.kr").toString();
  } catch (_) {
    return value;
  }
}

let cachedGnbBannerCatalog = null;
function readReferenceGnbBannerCatalog() {
  if (cachedGnbBannerCatalog) return cachedGnbBannerCatalog;
  const catalog = {};
  const artifactPath = path.join(GNB_STATE_DIR, "www-lge-co-kr-home__제품-소모품.open.cdp.json");
  if (!fs.existsSync(artifactPath)) {
    cachedGnbBannerCatalog = catalog;
    return catalog;
  }
  try {
    const payload = readJsonFile(artifactPath);
    const strings = Array.isArray(payload?.strings) ? payload.strings : [];
    const isDisplayAsset = (value) =>
      /^https:\/\/www\.lge\.co\.kr\/kr\/upload\/admin\/display\/displayObject\//.test(String(value || ""));
    const bannerStarts = [];
    strings.forEach((value, index) => {
      if (value === "CommonPcGnb_banner_list__am9D6") bannerStarts.push(index);
    });
    const isBannerKey = (value) => {
      const text = String(value || "").trim();
      return (
        text &&
        text.includes("-") &&
        !text.startsWith("/") &&
        !text.startsWith("http") &&
        !text.includes("__") &&
        !text.includes("display:") &&
        !text.includes("search=")
      );
    };
    const isBannerHref = (value) => {
      const text = String(value || "").trim();
      if (!text) return false;
      if (isDisplayAsset(text)) return false;
      return text.startsWith("/") || text.startsWith("https://www.lge.co.kr/");
    };
    bannerStarts.forEach((start, index) => {
      const nextBannerStart = bannerStarts[index + 1] ?? strings.length;
      const nextPanelStart = strings.findIndex((value, candidateIndex) => candidateIndex > start && value === "CommonPcGnb_nav_cate_list__BYpir");
      const end = nextPanelStart === -1 ? nextBannerStart : Math.min(nextBannerStart, nextPanelStart);
      for (let cursor = start + 1; cursor < end - 2; cursor += 1) {
        const key = String(strings[cursor] || "").trim();
        const href = String(strings[cursor + 1] || "").trim();
        if (!isBannerKey(key) || !isBannerHref(href)) continue;
        let imageUrl = "";
        for (let lookahead = cursor + 2; lookahead < Math.min(end, cursor + 12); lookahead += 1) {
          const candidate = String(strings[lookahead] || "").trim();
          if (isDisplayAsset(candidate)) {
            imageUrl = candidate;
            break;
          }
        }
        if (!imageUrl) continue;
        catalog[key] = {
          key,
          href: normalizeLgeUrl(href),
          imageUrl,
          kind: /300x300/.test(imageUrl) ? "featured" : "thumb",
        };
      }
    });
    if (Object.keys(catalog).length === 0) {
      cachedGnbBannerCatalog = {};
      return cachedGnbBannerCatalog;
    }
  } catch (_) {
    cachedGnbBannerCatalog = {};
    return cachedGnbBannerCatalog;
  }
  cachedGnbBannerCatalog = catalog;
  return catalog;
}

function buildGnbWorkbench(pageId, menu) {
  const normalizedPageId = String(pageId || "home").trim() || "home";
  const normalizedMenu = String(menu || "제품/소모품").trim() || "제품/소모품";
  const { referenceUrl, workingUrl } = getGnbWorkbenchSourceUrls(normalizedPageId);
  const reference = readGnbStateArtifact(referenceUrl, normalizedMenu);
  const working = readGnbStateArtifact(workingUrl, normalizedMenu);
  const referenceSummary = summarizeGnbStateArtifact(reference);
  const workingSummary = summarizeGnbStateArtifact(working);
  const refRect = referenceSummary.after?.panelRect || null;
  const workRect = workingSummary.after?.panelRect || null;
  const checks = [];
  if (!reference) checks.push({ id: "reference-artifact", status: "missing", detail: `missing ${referenceUrl}` });
  if (!working) checks.push({ id: "working-artifact", status: "missing", detail: `missing ${workingUrl}` });
  if (reference) {
    checks.push({
      id: "reference-open-state",
      status: referenceSummary.openStateValid ? "pass" : "fail",
      detail: referenceSummary.openStateValid ? "reference open snapshot valid" : "reference open snapshot did not actually open",
    });
  }
  if (working) {
    checks.push({
      id: "working-open-state",
      status: workingSummary.openStateValid ? "pass" : "fail",
      detail: workingSummary.openStateValid ? "working open snapshot valid" : "working open snapshot did not actually open",
    });
  }
  if (refRect && workRect) {
    checks.push({
      id: "panel-rect",
      status:
        refRect.x === workRect.x &&
        refRect.y === workRect.y &&
        refRect.width === workRect.width &&
        refRect.height === workRect.height
          ? "pass"
          : "fail",
      detail:
        `reference x=${refRect.x} y=${refRect.y} w=${refRect.width} h=${refRect.height} | ` +
        `working x=${workRect.x} y=${workRect.y} w=${workRect.width} h=${workRect.height}`,
    });
  }
  if (referenceSummary.after && workingSummary.after) {
    checks.push({
      id: "depth2-count",
      status: referenceSummary.after.depth2Count === workingSummary.after.depth2Count ? "pass" : "fail",
      detail: `reference=${referenceSummary.after.depth2Count} working=${workingSummary.after.depth2Count}`,
    });
    checks.push({
      id: "depth3-visible-count",
      status: referenceSummary.after.visibleDepth3Count === workingSummary.after.visibleDepth3Count ? "pass" : "fail",
      detail: `reference=${referenceSummary.after.visibleDepth3Count} working=${workingSummary.after.visibleDepth3Count}`,
    });
    checks.push({
      id: "active-depth2",
      status: referenceSummary.after.activeDepth2Label === workingSummary.after.activeDepth2Label ? "pass" : "fail",
      detail: `reference=${referenceSummary.after.activeDepth2Label || "n/a"} working=${workingSummary.after.activeDepth2Label || "n/a"}`,
    });
  }
  const menuType = (summary) => ((summary?.after?.depth2Count || 0) > 0 ? "with-depth2" : "simple-panel");
  const rectMetrics = (a, b) => {
    if (!a || !b) return null;
    const dx = Math.abs((a.x || 0) - (b.x || 0));
    const dy = Math.abs((a.y || 0) - (b.y || 0));
    const dw = Math.abs((a.width || 0) - (b.width || 0));
    const dh = Math.abs((a.height || 0) - (b.height || 0));
    return { dx, dy, dw, dh, worst: Math.max(dx, dy, dw, dh) };
  };
  const gnbGroupChecks = [];
  if (reference) {
    gnbGroupChecks.push({
      id: "gnb-open-state-reference",
      groupId: "openState",
      checkType: "valid",
      status: referenceSummary.openStateValid ? "pass" : "fail",
      detail: referenceSummary.openStateValid ? "reference open snapshot valid" : "reference open snapshot invalid",
    });
  }
  if (working) {
    gnbGroupChecks.push({
      id: "gnb-open-state-working",
      groupId: "openState",
      checkType: "valid",
      status: workingSummary.openStateValid ? "pass" : "fail",
      detail: workingSummary.openStateValid ? "working open snapshot valid" : "working open snapshot invalid",
    });
  }
  if (referenceSummary.after && workingSummary.after) {
    const typeRef = menuType(referenceSummary);
    const typeWork = menuType(workingSummary);
    gnbGroupChecks.push({
      id: "gnb-menu-type",
      groupId: "menuType",
      checkType: "value",
      status: typeRef === typeWork ? "pass" : "fail",
      detail: `reference=${typeRef} working=${typeWork}`,
    });
    const panelMetrics = rectMetrics(referenceSummary.after.panelRect, workingSummary.after.panelRect);
    if (panelMetrics) {
      gnbGroupChecks.push({
        id: "gnb-panel-rect",
        groupId: "panel",
        checkType: "rect",
        status: panelMetrics.worst > 4 ? "fail" : panelMetrics.worst > 2 ? "warning" : "pass",
        detail: `dx=${panelMetrics.dx} dy=${panelMetrics.dy} dw=${panelMetrics.dw} dh=${panelMetrics.dh}`,
        metrics: panelMetrics,
      });
    } else {
      gnbGroupChecks.push({
        id: "gnb-panel-rect",
        groupId: "panel",
        checkType: "rect",
        status: "warning",
        detail: `reference=${referenceSummary.after.panelRect ? "present" : "missing"} working=${workingSummary.after.panelRect ? "present" : "missing"}`,
      });
    }
    const stripMetrics = rectMetrics(referenceSummary.after.topStripRect, workingSummary.after.topStripRect);
    if (stripMetrics) {
      gnbGroupChecks.push({
        id: "gnb-top-strip-rect",
        groupId: "topStrip",
        checkType: "rect",
        status: stripMetrics.worst > 4 ? "fail" : stripMetrics.worst > 2 ? "warning" : "pass",
        detail: `dx=${stripMetrics.dx} dy=${stripMetrics.dy} dw=${stripMetrics.dw} dh=${stripMetrics.dh}`,
        metrics: stripMetrics,
      });
    }
    gnbGroupChecks.push({
      id: "gnb-depth2-count",
      groupId: "depth2",
      checkType: "count",
      status: referenceSummary.after.depth2Count === workingSummary.after.depth2Count ? "pass" : "fail",
      detail: `reference=${referenceSummary.after.depth2Count} working=${workingSummary.after.depth2Count}`,
    });
    gnbGroupChecks.push({
      id: "gnb-visible-depth3-count",
      groupId: "visibleDepth3",
      checkType: "count",
      status: referenceSummary.after.visibleDepth3Count === workingSummary.after.visibleDepth3Count ? "pass" : "fail",
      detail: `reference=${referenceSummary.after.visibleDepth3Count} working=${workingSummary.after.visibleDepth3Count}`,
    });
    const refLabels = referenceSummary.after.depth2Labels || [];
    const workLabels = workingSummary.after.depth2Labels || [];
    gnbGroupChecks.push({
      id: "gnb-depth2-labels",
      groupId: "depth2",
      checkType: "labels",
      status: JSON.stringify(refLabels) === JSON.stringify(workLabels) ? "pass" : "warning",
      detail: `reference=${refLabels.join(" | ") || "n/a"} working=${workLabels.join(" | ") || "n/a"}`,
    });
    gnbGroupChecks.push({
      id: "gnb-active-depth2",
      groupId: "activeDepth2",
      checkType: "value",
      status: referenceSummary.after.activeDepth2Label === workingSummary.after.activeDepth2Label ? "pass" : "fail",
      detail: `reference=${referenceSummary.after.activeDepth2Label || "n/a"} working=${workingSummary.after.activeDepth2Label || "n/a"}`,
    });
  }
  const groupSummary = buildPdpCaptureCheckSummary(gnbGroupChecks);
  return {
    pageId: normalizedPageId,
    menu: normalizedMenu,
    referenceUrl,
    workingUrl,
    reference,
    working,
    referenceSummary,
    workingSummary,
    checks,
    groupChecks: gnbGroupChecks,
    groupSummary,
  };
}

function buildPdpWorkbench(pageId, viewportProfile) {
  const targets = readWorkbenchTargets();
  const normalizedPageId = String(pageId || "category-tvs").trim() || "category-tvs";
  const normalizedViewportProfile = String(viewportProfile || "pc").trim() || "pc";
  const pdpContext = resolvePdpRuntimeContext(normalizedPageId);
  const workbenchPageId = pdpContext?.runtimePageId || normalizedPageId;
  const pdpTarget = (targets.pdpTargets || []).find(
    (item) => item.pageId === workbenchPageId && item.viewportProfile === normalizedViewportProfile
  ) || null;
  const plpTarget = (targets.plpTargets || []).find(
    (item) => item.pageId === workbenchPageId && item.viewportProfile === normalizedViewportProfile
  ) || null;
  const checks = [];
  if (!pdpTarget) {
    checks.push({ id: "target-exists", status: "fail", detail: "pdp target not found" });
  } else {
    checks.push({
      id: "target-exists",
      status: "pass",
      detail: `representativeCount=${pdpTarget.representativeCount}`,
    });
    checks.push({
      id: "representative-count",
      status: pdpTarget.representativeCount > 0 ? "pass" : "fail",
      detail: String(pdpTarget.representativeCount || 0),
    });
    checks.push({
      id: "fallback-used",
      status: pdpTarget.fallbackUsed ? "warning" : "pass",
      detail: pdpTarget.fallbackUsed ? "using fallback representative set" : "direct representative set",
    });
  }
  const representativeProducts = pdpContext
    ? [
        {
          href: pdpContext.href,
          pathname: pdpContext.route,
          text: pdpContext.title,
        },
      ]
    : (pdpTarget?.representativeProducts || []);
  const captures = representativeProducts.map((item) => {
    const matched = findPdpVisualCapture(workbenchPageId, normalizedViewportProfile, item.href, "reference");
    const working = findPdpVisualCapture(workbenchPageId, normalizedViewportProfile, item.href, "working");
    const referenceGroups = findPdpGroupEntry(workbenchPageId, normalizedViewportProfile, item.href, "reference");
    const workingGroups = findPdpGroupEntry(workbenchPageId, normalizedViewportProfile, item.href, "working");
    const groupChecks = buildPdpGroupChecks(referenceGroups?.groups, workingGroups?.groups);
    return {
      ...item,
      referenceCapture: matched
        ? {
            imageUrl: toVisualUrl(matched.artifact?.screenshotPath),
            htmlUrl: toVisualUrl(matched.artifact?.htmlPath),
            metadataUrl: toVisualUrl(matched.artifact?.metadataPath),
            capturedAt: matched.capturedAt,
            capturedUrl: matched.capturedUrl,
            title: matched.title || "",
          }
        : null,
      referenceGroups,
      workingCapture: working
        ? {
            imageUrl: toVisualUrl(working.artifact?.screenshotPath),
            htmlUrl: toVisualUrl(working.artifact?.htmlPath),
            metadataUrl: toVisualUrl(working.artifact?.metadataPath),
            capturedAt: working.capturedAt,
            capturedUrl: working.capturedUrl,
            title: working.title || "",
          }
        : null,
      workingGroups,
      groupChecks,
      groupSummary: buildPdpCaptureCheckSummary(groupChecks),
    };
  });
  if (captures.length > 0) {
    const capturedCount = captures.filter((item) => item.referenceCapture?.imageUrl).length;
    checks.push({
      id: "reference-capture-count",
      status: capturedCount === captures.length ? "pass" : capturedCount > 0 ? "warning" : "fail",
      detail: `${capturedCount}/${captures.length}`,
    });
    const workingCount = captures.filter((item) => item.workingCapture?.imageUrl).length;
    checks.push({
      id: "working-capture-count",
      status: workingCount === captures.length ? "pass" : workingCount > 0 ? "warning" : "fail",
      detail: `${workingCount}/${captures.length}`,
    });
    const referenceGroupCount = captures.filter((item) => item.referenceGroups?.groups?.summary || item.referenceGroups?.groups?.gallery).length;
    checks.push({
      id: "reference-group-count",
      status: referenceGroupCount === captures.length ? "pass" : referenceGroupCount > 0 ? "warning" : "fail",
      detail: `${referenceGroupCount}/${captures.length}`,
    });
    const workingGroupCount = captures.filter((item) => item.workingGroups?.groups?.summary || item.workingGroups?.groups?.gallery).length;
    checks.push({
      id: "working-group-count",
      status: workingGroupCount === captures.length ? "pass" : workingGroupCount > 0 ? "warning" : "fail",
      detail: `${workingGroupCount}/${captures.length}`,
    });
  }
  return {
    pageId: normalizedPageId,
    runtimePageId: workbenchPageId,
    viewportProfile: normalizedViewportProfile,
    generatedAt: targets.generatedAt || null,
    pdpTarget,
    plpTarget,
    captures,
    checks,
    groupSummary: buildPdpWorkbenchGroupSummary(captures),
  };
}

function buildPlpWorkbench(pageId, viewportProfile) {
  const targets = readWorkbenchTargets();
  const normalizedPageId = String(pageId || "category-tvs").trim() || "category-tvs";
  const normalizedViewportProfile = String(viewportProfile || "pc").trim() || "pc";
  const plpTarget = (targets.plpTargets || []).find(
    (item) => item.pageId === normalizedPageId && item.viewportProfile === normalizedViewportProfile
  ) || null;
  const checks = [];
  if (!plpTarget) {
    checks.push({ id: "target-exists", status: "fail", detail: "plp target not found" });
  } else {
    checks.push({ id: "target-exists", status: "pass", detail: `representativeCount=${plpTarget.representativeCount}` });
    checks.push({
      id: "representative-count",
      status: plpTarget.representativeCount > 0 ? "pass" : "fail",
      detail: String(plpTarget.representativeCount || 0),
    });
    checks.push({
      id: "fallback-used",
      status: plpTarget.fallbackFromViewportProfile ? "warning" : "pass",
      detail: plpTarget.fallbackFromViewportProfile
        ? `using fallback representative set from ${plpTarget.fallbackFromViewportProfile}`
        : "direct representative set",
    });
  }
  const referenceCapture = findPlpVisualCapture(normalizedPageId, normalizedViewportProfile, "reference");
  const workingCapture = findPlpVisualCapture(normalizedPageId, normalizedViewportProfile, "working");
  const referenceGroups = findPlpGroupEntry(normalizedPageId, normalizedViewportProfile, "reference");
  const workingGroups = findPlpGroupEntry(normalizedPageId, normalizedViewportProfile, "working");
  const groupChecks = buildPlpGroupChecks(referenceGroups, workingGroups);
  checks.push({
    id: "reference-capture",
    status: referenceCapture?.artifact?.screenshotPath ? "pass" : "fail",
    detail: referenceCapture?.artifact?.screenshotPath ? "available" : "missing",
  });
  checks.push({
    id: "working-capture",
    status: workingCapture?.artifact?.screenshotPath ? "pass" : "fail",
    detail: workingCapture?.artifact?.screenshotPath ? "available" : "missing",
  });
  checks.push({
    id: "reference-group-entry",
    status: referenceGroups?.groups ? "pass" : "fail",
    detail: referenceGroups?.groups ? "available" : "missing",
  });
  checks.push({
    id: "working-group-entry",
    status: workingGroups?.groups ? "pass" : "fail",
    detail: workingGroups?.groups ? "available" : "missing",
  });
  return {
    pageId: normalizedPageId,
    viewportProfile: normalizedViewportProfile,
    generatedAt: targets.generatedAt || null,
    plpTarget,
    referenceGroups,
    workingGroups,
    groupChecks,
    groupSummary: buildPdpCaptureCheckSummary(groupChecks),
    referenceCapture: referenceCapture
      ? {
          imageUrl: toVisualUrl(referenceCapture.artifact?.screenshotPath),
          htmlUrl: toVisualUrl(referenceCapture.artifact?.htmlPath),
          metadataUrl: toVisualUrl(referenceCapture.artifact?.metadataPath),
          capturedAt: referenceCapture.capturedAt,
          capturedUrl: referenceCapture.capturedUrl,
          title: referenceCapture.title || "",
        }
      : null,
    workingCapture: workingCapture
      ? {
          imageUrl: toVisualUrl(workingCapture.artifact?.screenshotPath),
          htmlUrl: toVisualUrl(workingCapture.artifact?.htmlPath),
          metadataUrl: toVisualUrl(workingCapture.artifact?.metadataPath),
          capturedAt: workingCapture.capturedAt,
          capturedUrl: workingCapture.capturedUrl,
          title: workingCapture.title || "",
        }
      : null,
    checks,
  };
}

function buildServicePageWorkbench(pageId, viewportProfile) {
  const normalizedPageId = String(pageId || "support").trim() || "support";
  const normalizedViewportProfile = String(viewportProfile || "pc").trim() || "pc";
  const sourceUrlMap = {
    support: "https://www.lge.co.kr/support",
    bestshop: "https://www.lge.co.kr/bestshop",
    "care-solutions": "https://www.lge.co.kr/care-solutions",
    "care-solutions-pdp": "https://www.lge.co.kr/care-solutions/water-purifiers/wd523vc?dpType=careTab&subscCategoryKeyId=246021",
    "homestyle-home": "https://homestyle.lge.co.kr/home",
    "homestyle-pdp": "https://homestyle.lge.co.kr/item?productId=G26030036505",
  };
  const sourceUrl = sourceUrlMap[normalizedPageId] || null;
  const referenceCapture = findServicePageVisualCapture(normalizedPageId, normalizedViewportProfile, "reference");
  const workingCapture = findServicePageVisualCapture(normalizedPageId, normalizedViewportProfile, "working");
  const referenceGroups = resolveServiceGroupEntry(normalizedPageId, normalizedViewportProfile, "reference");
  const workingGroups = resolveServiceGroupEntry(normalizedPageId, normalizedViewportProfile, "working");
  const normalizedReferenceGroups = normalizeGroupMap(referenceGroups?.groups);
  const normalizedWorkingGroups = normalizeGroupMap(workingGroups?.groups);
  const groupIdsByPage = {
    support: ["mainService", "notice", "tipsBanner", "bestcare"],
    bestshop: ["hero", "shortcut", "review", "brandBanner"],
    "care-solutions": ["hero", "ranking", "benefit", "tabs", "careBanner"],
    "care-solutions-pdp": ["visual", "detailInfo", "noticeBanner", "reviewInfo"],
    "homestyle-home": ["quickMenu", "labelBanner", "brandStory"],
    "homestyle-pdp": ["detailInfo", "bestProduct", "review", "qna", "guides", "seller"],
  };
  const groupChecks = buildGroupChecks(normalizedReferenceGroups, normalizedWorkingGroups, groupIdsByPage[normalizedPageId] || []);
  const checks = [
    {
      id: "source-url",
      status: sourceUrl ? "pass" : "fail",
      detail: sourceUrl || "unknown service page",
    },
    {
      id: "reference-capture",
      status: referenceCapture?.artifact?.screenshotPath ? "pass" : "fail",
      detail: referenceCapture?.artifact?.screenshotPath ? "available" : "missing",
    },
    {
      id: "working-capture",
      status: workingCapture?.artifact?.screenshotPath ? "pass" : "fail",
      detail: workingCapture?.artifact?.screenshotPath ? "available" : "missing",
    },
    {
      id: "title-match",
      status:
        referenceCapture?.title && workingCapture?.title
          ? referenceCapture.title === workingCapture.title ? "pass" : "warning"
          : "warning",
      detail: `reference=${referenceCapture?.title || ""} working=${workingCapture?.title || ""}`,
    },
    {
      id: "reference-groups",
      status: referenceGroups?.groups ? "pass" : "fail",
      detail: referenceGroups?.groups ? "available" : "missing",
    },
    {
      id: "working-groups",
      status: workingGroups?.groups ? "pass" : "fail",
      detail: workingGroups?.groups ? "available" : "missing",
    },
  ];
  return {
    pageId: normalizedPageId,
    viewportProfile: normalizedViewportProfile,
    generatedAt: readServicePageVisualIndex().generatedAt || null,
    sourceUrl,
    referenceGroups: referenceGroups ? { ...referenceGroups, groups: normalizedReferenceGroups } : null,
    workingGroups: workingGroups ? { ...workingGroups, groups: normalizedWorkingGroups } : null,
    groupChecks,
    groupSummary: buildPdpCaptureCheckSummary(groupChecks),
    referenceCapture: referenceCapture
      ? {
          imageUrl: toVisualUrl(referenceCapture.artifact?.screenshotPath),
          htmlUrl: toVisualUrl(referenceCapture.artifact?.htmlPath),
          metadataUrl: toVisualUrl(referenceCapture.artifact?.metadataPath),
          capturedAt: referenceCapture.capturedAt,
          capturedUrl: referenceCapture.capturedUrl,
          title: referenceCapture.title || "",
        }
      : null,
    workingCapture: workingCapture
      ? {
          imageUrl: toVisualUrl(workingCapture.artifact?.screenshotPath),
          htmlUrl: toVisualUrl(workingCapture.artifact?.htmlPath),
          metadataUrl: toVisualUrl(workingCapture.artifact?.metadataPath),
          capturedAt: workingCapture.capturedAt,
          capturedUrl: workingCapture.capturedUrl,
          title: workingCapture.title || "",
        }
      : null,
    checks,
  };
}

