function hasRenderableServiceGroups(groups) {
  const normalized = normalizeGroupMap(groups);
  return Object.values(normalized || {}).some((group) => group?.found);
}

function resolveServiceGroupEntry(pageId, viewportProfile, sourceType = "reference") {
  const requested = findServiceGroupEntry(pageId, viewportProfile, sourceType);
  if (sourceType !== "working") {
    return requested ? { ...requested, groups: normalizeGroupMap(requested.groups) } : null;
  }
  const normalizedRequested = normalizeGroupMap(requested?.groups);
  if (hasRenderableServiceGroups(normalizedRequested)) {
    return requested ? { ...requested, groups: normalizedRequested } : null;
  }
  const referenceEntry = findServiceGroupEntry(pageId, viewportProfile, "reference");
  const normalizedReference = normalizeGroupMap(referenceEntry?.groups);
  if (!hasRenderableServiceGroups(normalizedReference)) {
    return requested ? { ...requested, groups: normalizedRequested } : null;
  }
  return {
    ...(requested || {}),
    pageId: String(pageId || "").trim(),
    viewportProfile: String(viewportProfile || "pc").trim() || "pc",
    sourceType: "working",
    groups: normalizedReference,
    fallbackFromReference: true,
  };
}

function normalizeGroupMap(groups) {
  const source = groups && typeof groups === "object" ? groups : {};
  return Object.fromEntries(
    Object.entries(source).map(([groupId, value]) => [
      groupId,
      {
        ...value,
        found:
          typeof value?.found === "boolean"
            ? value.found
            : Boolean(value?.matchCount > 0 || value?.rect || value?.selector),
      },
    ])
  );
}

function findPlpGroupEntry(pageId, viewportProfile, sourceType = "reference") {
  const groupIndex = readPlpGroupIndex();
  return (
    (groupIndex.entries || []).find(
      (entry) =>
        entry.pageId === pageId &&
        entry.viewportProfile === viewportProfile &&
        String(entry.sourceType || "reference") === sourceType
    ) || null
  );
}

function findPdpGroupEntry(pageId, viewportProfile, href, sourceType = "reference") {
  const groupIndex = readPdpGroupIndex();
  return (
    (groupIndex.entries || []).find(
      (entry) =>
        entry.pageId === pageId &&
        entry.viewportProfile === viewportProfile &&
        entry.href === href &&
        String(entry.sourceType || "reference") === sourceType
    ) || null
  );
}

function buildGroupChecks(referenceGroups, workingGroups, groupIds) {
  const checks = [];
  for (const groupId of groupIds) {
    const reference = referenceGroups?.[groupId] || null;
    const working = workingGroups?.[groupId] || null;
    checks.push({
      id: `group-${groupId}-presence`,
      groupId,
      checkType: "presence",
      status:
        reference?.found && working?.found
          ? "pass"
          : !reference?.found && !working?.found
            ? "warning"
            : "fail",
      detail: `reference=${reference?.found ? "found" : "missing"} working=${working?.found ? "found" : "missing"}`,
    });
    if (reference?.found && working?.found && (!reference?.rect || !working?.rect)) {
      checks.push({
        id: `group-${groupId}-rect`,
        groupId,
        checkType: "rect",
        status: "warning",
        detail: `incomplete-rect reference=${reference?.rect ? "present" : "missing"} working=${working?.rect ? "present" : "missing"}`,
      });
    } else if (reference?.rect && working?.rect) {
      const dx = Math.abs((reference.rect.x || 0) - (working.rect.x || 0));
      const dy = Math.abs((reference.rect.y || 0) - (working.rect.y || 0));
      const dw = Math.abs((reference.rect.width || 0) - (working.rect.width || 0));
      const dh = Math.abs((reference.rect.height || 0) - (working.rect.height || 0));
      const worst = Math.max(dx, dy, dw, dh);
      checks.push({
        id: `group-${groupId}-rect`,
        groupId,
        checkType: "rect",
        status: worst > 4 ? "fail" : worst > 2 ? "warning" : "pass",
        detail: `dx=${dx} dy=${dy} dw=${dw} dh=${dh}`,
        metrics: { dx, dy, dw, dh, worst },
      });
    }
  }
  return checks;
}

function summarizeStatusCounts(items) {
  const counts = { pass: 0, warning: 0, fail: 0 };
  for (const item of items || []) {
    if (item?.status === "fail") counts.fail += 1;
    else if (item?.status === "warning") counts.warning += 1;
    else if (item?.status === "pass") counts.pass += 1;
  }
  return counts;
}

function buildPdpCaptureCheckSummary(groupChecks) {
  const checks = Array.isArray(groupChecks) ? groupChecks : [];
  const grouped = new Map();
  for (const check of checks) {
    const groupId = check.groupId || "unknown";
    if (!grouped.has(groupId)) grouped.set(groupId, []);
    grouped.get(groupId).push(check);
  }
  const groups = Array.from(grouped.entries()).map(([groupId, items]) => {
    const counts = summarizeStatusCounts(items);
    return {
      groupId,
      status: counts.fail > 0 ? "fail" : counts.warning > 0 ? "warning" : "pass",
      counts,
      checks: items,
    };
  });
  groups.sort((a, b) => {
    const rank = { fail: 0, warning: 1, pass: 2 };
    return (rank[a.status] ?? 3) - (rank[b.status] ?? 3) || a.groupId.localeCompare(b.groupId);
  });
  const counts = summarizeStatusCounts(groups);
  return {
    status: counts.fail > 0 ? "fail" : counts.warning > 0 ? "warning" : "pass",
    counts,
    groups,
  };
}

function buildPdpWorkbenchGroupSummary(captures) {
  const summaryByGroup = new Map();
  for (const capture of captures || []) {
    for (const group of capture.groupSummary?.groups || []) {
      if (!summaryByGroup.has(group.groupId)) {
        summaryByGroup.set(group.groupId, {
          groupId: group.groupId,
          pass: 0,
          warning: 0,
          fail: 0,
          samples: [],
        });
      }
      const item = summaryByGroup.get(group.groupId);
      item[group.status] += 1;
      if (group.status !== "pass" && item.samples.length < 3) {
        item.samples.push({
          href: capture.href,
          pathname: capture.pathname || capture.href,
          status: group.status,
          checks: group.checks.map((check) => ({
            id: check.id,
            status: check.status,
            detail: check.detail,
            metrics: check.metrics || null,
          })),
        });
      }
    }
  }
  const groups = Array.from(summaryByGroup.values()).map((item) => ({
    ...item,
    status: item.fail > 0 ? "fail" : item.warning > 0 ? "warning" : "pass",
  }));
  groups.sort((a, b) => {
    const rank = { fail: 0, warning: 1, pass: 2 };
    return (rank[a.status] ?? 3) - (rank[b.status] ?? 3) || a.groupId.localeCompare(b.groupId);
  });
  return {
    status: groups.some((item) => item.status === "fail")
      ? "fail"
      : groups.some((item) => item.status === "warning")
        ? "warning"
        : "pass",
    groups,
  };
}

function buildPlpGroupChecks(referenceEntry, workingEntry) {
  const groupIds = ["filter", "sort", "productGrid", "firstRow", "firstProduct", "banner"];
  const checks = buildGroupChecks(referenceEntry?.groups, workingEntry?.groups, groupIds);
  const fallbackWarning =
    referenceEntry?.fallbackFromViewportProfile ||
    workingEntry?.fallbackFromViewportProfile ||
    null;
  if (!fallbackWarning) return checks;
  const fallbackSensitive = new Set(["productGrid", "firstRow", "firstProduct"]);
  for (const group of checks.groups || []) {
    if (!fallbackSensitive.has(group.groupId)) continue;
    group.checks = (group.checks || []).map((check) => {
      if (check.checkType !== "presence") return check;
      const refMatched = Number(referenceEntry?.matchedProductCount || 0);
      const workMatched = Number(workingEntry?.matchedProductCount || 0);
      if ((refMatched === 0 || workMatched === 0) && check.status === "fail") {
        return {
          ...check,
          status: "warning",
          detail: `${check.detail} fallback=${fallbackWarning}`
        };
      }
      return check;
    });
    const statuses = (group.checks || []).map((item) => item.status);
    group.counts = {
      pass: statuses.filter((s) => s === "pass").length,
      warning: statuses.filter((s) => s === "warning").length,
      fail: statuses.filter((s) => s === "fail").length,
    };
    group.status = group.counts.fail
      ? "fail"
      : group.counts.warning
        ? "warning"
        : "pass";
  }
  checks.status = (checks.groups || []).some((item) => item.status === "fail")
    ? "fail"
    : (checks.groups || []).some((item) => item.status === "warning")
      ? "warning"
      : "pass";
  return checks;
}

function buildPdpGroupChecks(referenceGroups, workingGroups) {
  const groupIds = ["gallery", "summary", "price", "option", "sticky", "review", "qna"];
  return buildGroupChecks(referenceGroups, workingGroups, groupIds);
}

function toVisualUrl(filePath) {
  if (!filePath) return null;
  const normalized = path.normalize(filePath);
  if (!fs.existsSync(normalized)) return null;
  const visualRoot = path.normalize(VISUAL_DIR + path.sep);
  const normalizedFolded = normalized.toLowerCase();
  const visualRootFolded = visualRoot.toLowerCase();
  if (!normalizedFolded.startsWith(visualRootFolded)) return null;
  const relativePath = normalized.slice(visualRoot.length).replace(/\\/g, "/");
  return `/visual/${relativePath.split("/").map(encodeURIComponent).join("/")}`;
}

function getVisualCriticViewport(viewportProfile = "pc") {
  const normalized = normalizeViewportProfile(viewportProfile, "pc");
  if (normalized === "mo") return { width: 430, height: 1600 };
  if (normalized === "ta") return { width: 1024, height: 1600 };
  return { width: 1460, height: 1600 };
}

function buildInternalVisualCriticPreviewUrl(pageId, options = {}) {
  const normalizedPageId = String(pageId || "").trim();
  if (!normalizedPageId) return "";
  const params = new URLSearchParams();
  params.set("viewportProfile", String(options.viewportProfile || "pc").trim() || "pc");
  params.set("criticKey", INTERNAL_VISUAL_CRITIC_KEY);
  params.set("criticUserId", String(options.userId || "").trim());
  if (options.draftBuildId) params.set("draftBuildId", String(options.draftBuildId || "").trim());
  if (options.snapshotState) params.set("snapshotState", String(options.snapshotState || "").trim());
  if (options.sectionPreviewSlot) params.set("sectionPreviewSlot", String(options.sectionPreviewSlot || "").trim());
  return `http://127.0.0.1:${PORT}/clone-content/${encodeURIComponent(normalizedPageId)}?${params.toString()}`;
}

async function waitForVisualCaptureSettled(page, settleMs = 800) {
  try {
    await page.waitForFunction(
      () => document.readyState === "interactive" || document.readyState === "complete",
      { timeout: 10_000 }
    );
  } catch {}
  try {
    await page.waitForLoadState("load", { timeout: 5_000 });
  } catch {}
  try {
    await page.waitForLoadState("networkidle", { timeout: 3_000 });
  } catch {}
  try {
    await page.evaluate(async () => {
      if (!document.fonts?.ready) return;
      await Promise.race([
        document.fonts.ready.catch(() => null),
        new Promise((resolve) => setTimeout(resolve, 3_000)),
      ]);
    });
  } catch {}
  await page.waitForTimeout(Math.max(0, Number(settleMs || 0) || 0));
}

async function gotoForVisualCapture(page, url, options = {}) {
  const timeoutMs = Math.max(5_000, Number(options.timeoutMs || 45_000) || 45_000);
  const settleMs = Math.max(200, Number(options.settleMs || 800) || 800);
  const attempts = [
    { waitUntil: "domcontentloaded", timeout: Math.min(timeoutMs, 20_000) },
    { waitUntil: "load", timeout: Math.min(timeoutMs, 30_000) },
  ];
  let lastError = null;
  for (const attempt of attempts) {
    try {
      await page.goto(url, attempt);
      await waitForVisualCaptureSettled(page, settleMs);
      return;
    } catch (error) {
      lastError = error;
    }
  }
  throw lastError || new Error("visual_capture_navigation_failed");
}

async function captureUrlAsScreenshotDataUrl(targetUrl, viewportProfile = "pc", options = {}) {
  const url = String(targetUrl || "").trim();
  if (!url) return null;
  const { chromium } = require("playwright");
  const viewport = getVisualCriticViewport(viewportProfile);
  const baseTimeoutMs = Math.max(5_000, Number(options.timeoutMs || 45_000) || 45_000);
  const baseSettleMs = Math.max(200, Number(options.settleMs || 800) || 800);
  const attempts = [
    { timeoutMs: baseTimeoutMs, settleMs: baseSettleMs },
    { timeoutMs: baseTimeoutMs + 15_000, settleMs: baseSettleMs + 400 },
  ];
  let lastError = null;
  for (const attempt of attempts) {
    const browser = await chromium.launch({ headless: true });
    try {
      const page = await browser.newPage({ viewport });
      await gotoForVisualCapture(page, url, {
        ...options,
        timeoutMs: attempt.timeoutMs,
        settleMs: attempt.settleMs,
      });
      const buffer = await page.screenshot({
        type: "png",
        fullPage: Boolean(options?.fullPage),
      });
      return `data:image/png;base64,${buffer.toString("base64")}`;
    } catch (error) {
      lastError = error;
    } finally {
      await browser.close();
    }
  }
  throw lastError || new Error("visual_capture_failed");
}

async function fetchUrlTextWithTimeout(targetUrl = "", timeoutMs = 15_000) {
  const url = String(targetUrl || "").trim();
  if (!url) return "";
  const controller = new AbortController();
  const timer = setTimeout(() => controller.abort(new Error("fetch_timeout")), Math.max(1_000, Number(timeoutMs || 15_000) || 15_000));
  try {
    const response = await fetch(url, { signal: controller.signal });
    if (!response.ok) throw new Error(`fetch_failed:${response.status}`);
    return await response.text();
  } finally {
    clearTimeout(timer);
  }
}

function summarizeVisualPreviewHtml(html = "") {
  const source = String(html || "");
  const rendererSurface = source.includes("codex-v2-home-surface--tailwind")
    ? "tailwind"
    : source.includes("codex-v2-home-surface")
      ? "custom-v2"
      : source.includes("codex-home-composition-")
        ? "legacy-composition"
        : source.includes("data-codex-slot=\"hero\"") || source.includes("data-codex-slot=\"quickmenu\"")
          ? "slot-preview"
          : "unknown";
  return {
    rendererSurface,
    hasHero: source.includes("data-codex-slot=\"hero\""),
    hasQuickmenu: source.includes("data-codex-slot=\"quickmenu\""),
    hasTopShell: source.includes("data-codex-slot=\"home-top-composition-shell\""),
    hasTailwindSurface: source.includes("codex-v2-home-surface--tailwind"),
    hasV2Surface: source.includes("codex-v2-home-surface"),
    hasLegacyComposition: source.includes("codex-home-composition-"),
  };
}

function inferVisualCriticTargetSlots(builderInput = {}, buildResult = {}) {
  const targetComponents = toStringArray(builderInput?.generationOptions?.targetComponents);
  const explicitSlots = targetComponents
    .map((item) => inferSlotIdFromComponentId(item) || String(item || "").trim())
    .filter(Boolean);
  if (explicitSlots.length) {
    return Array.from(new Set(explicitSlots));
  }
  const reportSlots = safeObjectArray(buildResult?.report?.componentComposition, 40)
    .map((item) => String(item?.slotId || inferSlotIdFromComponentId(item?.componentId) || "").trim())
    .filter(Boolean);
  return Array.from(new Set(reportSlots));
}

async function captureVisualCriticPreviewBundle({
  userId = "",
  pageId = "",
  viewportProfile = "pc",
  draftBuildId = "",
  builderInput = {},
  buildResult = {},
  includeHtmlSummary = false,
} = {}) {
  const targetSlots = inferVisualCriticTargetSlots(builderInput, buildResult);
  const sectionPreviewSlot = targetSlots.length ? targetSlots.join(",") : "";
  const focusTargetSlots = sectionPreviewSlot ? targetSlots : [];
  const focusLabel =
    targetSlots.length > 1
      ? "selected cluster focus"
      : (sectionPreviewSlot ? "focus area" : "");
  const referenceAnchor = pickVisualCriticReferenceAnchor(builderInput, buildResult);
  const referenceImageUrl = referenceAnchor?.screenshotUrls?.[0] || null;
  const beforeUrl = buildInternalVisualCriticPreviewUrl(pageId, {
    userId,
    viewportProfile,
    draftBuildId,
    snapshotState: "before",
  });
  const afterUrl = buildInternalVisualCriticPreviewUrl(pageId, {
    userId,
    viewportProfile,
    draftBuildId,
    snapshotState: "after",
  });
  const focusBeforeUrl = sectionPreviewSlot
    ? buildInternalVisualCriticPreviewUrl(pageId, {
        userId,
        viewportProfile,
        draftBuildId,
        snapshotState: "before",
        sectionPreviewSlot,
      })
    : "";
  const focusAfterUrl = sectionPreviewSlot
    ? buildInternalVisualCriticPreviewUrl(pageId, {
        userId,
        viewportProfile,
        draftBuildId,
        snapshotState: "after",
        sectionPreviewSlot,
      })
    : "";
  console.log(
    `[visual-capture] request user=${userId} page=${pageId} viewport=${viewportProfile} build=${draftBuildId} slot=${sectionPreviewSlot || "full"} referenceAnchor=${referenceAnchor?.id || "none"}`
  );
  const capture = async (url, options = {}) => {
    if (!url) return null;
    return captureUrlAsScreenshotDataUrl(url, viewportProfile, options);
  };
  const beforeImageDataUrl = await capture(beforeUrl);
  const afterImageDataUrl = await capture(afterUrl);
  const focusBeforeImageDataUrl = focusBeforeUrl ? await capture(focusBeforeUrl) : null;
  const focusAfterImageDataUrl = focusAfterUrl ? await capture(focusAfterUrl) : null;
  const referenceImageDataUrl = referenceImageUrl ? await captureReferenceAssetDataUrl(referenceImageUrl, viewportProfile) : null;
  const htmlSummary = includeHtmlSummary
    ? {
        before: summarizeVisualPreviewHtml(await fetchUrlTextWithTimeout(beforeUrl).catch(() => "")),
        after: summarizeVisualPreviewHtml(await fetchUrlTextWithTimeout(afterUrl).catch(() => "")),
        focusBefore: focusBeforeUrl ? summarizeVisualPreviewHtml(await fetchUrlTextWithTimeout(focusBeforeUrl).catch(() => "")) : null,
        focusAfter: focusAfterUrl ? summarizeVisualPreviewHtml(await fetchUrlTextWithTimeout(focusAfterUrl).catch(() => "")) : null,
      }
    : null;
  return {
    targetSlots,
    sectionPreviewSlot,
    focusTargetSlots,
    focusLabel,
    referenceAnchor,
    referenceImageUrl,
    beforeUrl,
    afterUrl,
    focusBeforeUrl,
    focusAfterUrl,
    beforeImageDataUrl,
    afterImageDataUrl,
    focusBeforeImageDataUrl,
    focusAfterImageDataUrl,
    referenceImageDataUrl,
    htmlSummary,
  };
}

function buildReplayBuilderInputFromDraft(draftBuild = {}, pageId = "", viewportProfile = "pc") {
  const snapshot = draftBuild?.snapshotData && typeof draftBuild.snapshotData === "object" ? draftBuild.snapshotData : {};
  const changedComponentIds = toStringArray(snapshot?.changedComponentIds);
  const reportComponentComposition = safeObjectArray(draftBuild?.report?.componentComposition, 40);
  const componentIds = Array.from(
    new Set(
      (
        changedComponentIds.length
          ? changedComponentIds
          : reportComponentComposition
              .map((item) => String(item?.componentId || `${pageId}.${String(item?.slotId || "").trim()}`).trim())
              .filter(Boolean)
      )
    )
  );
  const suggestedFocusSlots = Array.from(
    new Set(
      (
        changedComponentIds.length
          ? changedComponentIds.map((item) => inferSlotIdFromComponentId(item)).filter(Boolean)
          : reportComponentComposition
              .map((item) => String(item?.slotId || inferSlotIdFromComponentId(item?.componentId) || "").trim())
              .filter(Boolean)
      )
    )
  );
  return {
    pageContext: {
      workspacePageId: String(pageId || "").trim(),
      viewportProfile: normalizeViewportProfile(viewportProfile, "pc"),
    },
    generationOptions: {
      patchDepth: String(snapshot?.patchDepth || "medium").trim() || "medium",
      interventionLayer: String(snapshot?.interventionLayer || "section-group").trim() || "section-group",
      targetComponents: componentIds,
    },
    approvedPlan: {
      builderBrief: {
        suggestedFocusSlots,
      },
    },
    systemContext: {
      designToolContext: {},
    },
  };
}

function summarizeSectionBlueprintKeys(sectionBlueprints = []) {
  return (Array.isArray(sectionBlueprints) ? sectionBlueprints : [])
    .map((item) => String(item?.slotId || "").trim())
    .filter(Boolean)
    .slice(0, 24);
}

function summarizeEditableComponentIds(editableComponents = []) {
  return (Array.isArray(editableComponents) ? editableComponents : [])
    .map((item) => String(item?.componentId || "").trim())
    .filter(Boolean)
    .slice(0, 48);
}

