function getDefaultViewportCanvasWidth(pageId, viewportProfile = "pc") {
  const normalizedPageId = String(pageId || "").trim();
  const normalizedViewport =
    normalizedPageId === "home"
      ? normalizeHomeViewportProfile(viewportProfile, "pc")
      : normalizeViewportProfile(viewportProfile, "pc");
  if (normalizedPageId === "home") {
    if (normalizedViewport === "mo") return 390;
    if (normalizedViewport === "ta") return 1024;
    return HOME_LAYOUT_TOKENS.desktopCanvasWidth;
  }
  if (normalizedViewport === "mo") return 390;
  if (normalizedViewport === "ta") return 1024;
  return 1440;
}

function buildShareSectionRects(pageId, component = {}, mediaSpec = {}, viewportProfile = "pc") {
  const normalizedPageId = String(pageId || "").trim();
  const normalizedViewport =
    normalizedPageId === "home"
      ? normalizeHomeViewportProfile(viewportProfile, "pc")
      : normalizeViewportProfile(viewportProfile, "pc");
  const measuredScale = mediaSpec?.measuredScale && typeof mediaSpec.measuredScale === "object" ? mediaSpec.measuredScale : null;
  const viewportWidth = getDefaultViewportCanvasWidth(normalizedPageId, normalizedViewport);
  const fallbackContentWidth =
    component.containerMode === "full"
      ? viewportWidth
      : normalizedViewport === "mo"
        ? viewportWidth
        : normalizedViewport === "ta"
          ? 960
          : 1320;
  const sectionWidth =
    Number(measuredScale?.slotWidth) ||
    (normalizedPageId === "home"
      ? (component.containerMode === "full" ? HOME_LAYOUT_TOKENS.shellWideWidth : HOME_LAYOUT_TOKENS.desktopCanvasWidth)
      : viewportWidth);
  const contentWidth =
    Number(measuredScale?.contentWidth) ||
    (normalizedPageId === "home"
      ? (component.containerMode === "full" ? HOME_LAYOUT_TOKENS.shellWideWidth : HOME_LAYOUT_TOKENS.shellNarrowWidth)
      : fallbackContentWidth);
  const insetLeft =
    Number(measuredScale?.contentInsetLeft) ||
    Number(measuredScale?.usableBandLeft) ||
    Math.max(0, Math.round((sectionWidth - contentWidth) / 2));
  const insetRight =
    Number(measuredScale?.contentInsetRight) ||
    (Number(measuredScale?.usableBandRight)
      ? Math.max(0, sectionWidth - Number(measuredScale?.usableBandRight))
      : Math.max(0, Math.round((sectionWidth - contentWidth) / 2)));
  const sectionRect = {
    width: sectionWidth,
    viewportWidth,
    left: 0,
    right: sectionWidth,
  };
  const contentRect = {
    width: contentWidth,
    left: insetLeft,
    right: Math.max(0, sectionWidth - insetRight),
  };
  return { sectionRect, contentRect };
}

function getHomeSectionContract(slotId = "", viewportProfile = "pc") {
  const normalizedSlotId = String(slotId || "").trim();
  const normalizedViewport = normalizeHomeViewportProfile(viewportProfile, "pc");
  const renderProfile = getHomeDesktopRenderProfile(normalizedSlotId) || {};
  const measuredScale = getHomeComponentScaleToken(normalizedSlotId, normalizedViewport) || null;
  const sectionWidth =
    Number(measuredScale?.slotWidth) ||
    (normalizedViewport === "mo"
      ? 390
      : renderProfile.containerMode === "full"
        ? HOME_LAYOUT_TOKENS.shellWideWidth
        : HOME_LAYOUT_TOKENS.desktopCanvasWidth);
  const contentWidth =
    Number(measuredScale?.contentWidth) ||
    (normalizedViewport === "mo"
      ? 390
      : renderProfile.containerMode === "full"
        ? HOME_LAYOUT_TOKENS.shellWideWidth
        : HOME_LAYOUT_TOKENS.shellNarrowWidth);
  const mediaWidth = Number(measuredScale?.imageWidth) || null;
  const mediaHeight = Number(measuredScale?.imageHeight) || null;
  return {
    slotId: normalizedSlotId,
    viewportProfile: normalizedViewport,
    sectionWidth,
    contentWidth,
    mediaWidth,
    mediaHeight,
    containerMode: renderProfile.containerMode || (normalizedSlotId === "summary-banner-2" ? "full" : "narrow"),
    archetype: renderProfile.archetype || "section",
  };
}

function buildHomeSectionContractStyle(slotId = "", viewportProfile = "pc") {
  const contract = getHomeSectionContract(slotId, viewportProfile);
  const styleParts = [];
  if (contract.sectionWidth) styleParts.push(`--codex-section-width:${contract.sectionWidth}px`);
  if (contract.contentWidth) styleParts.push(`--codex-content-width:${contract.contentWidth}px`);
  if (contract.mediaWidth) styleParts.push(`--codex-media-width:${contract.mediaWidth}px`);
  if (contract.mediaHeight) styleParts.push(`--codex-media-height:${contract.mediaHeight}px`);
  return styleParts.join(";");
}

function buildShareImageZones(pageId, slotId, component = {}, mediaSpec = {}, viewportProfile = "pc") {
  const measuredScale = mediaSpec?.measuredScale && typeof mediaSpec.measuredScale === "object" ? mediaSpec.measuredScale : null;
  const imageWidth = Number(measuredScale?.imageWidth || 0);
  const imageHeight = Number(measuredScale?.imageHeight || 0);
  const fit = String(mediaSpec?.fit || measuredScale?.imageFit || "").trim() || "contain";
  const zones = [];
  if (imageWidth || imageHeight) {
    zones.push({
      id: `${slotId || "section"}-media-primary`,
      kind: component.kind === "gallery" ? "gallery" : "image",
      fit,
      width: imageWidth || null,
      height: imageHeight || null,
    });
  }
  if (!zones.length && Array.isArray(mediaSpec?.notes) && mediaSpec.notes.length) {
    zones.push({
      id: `${slotId || "section"}-media-guidance`,
      kind: "guidance",
      fit,
      notes: mediaSpec.notes.slice(0, 2),
    });
  }
  return zones;
}

function inferShareReplacementMode(pageId, component = {}, patchBridge = {}, mediaSpec = {}) {
  const normalizedPageId = String(pageId || "").trim();
  const kind = String(component.kind || patchBridge.archetype || "").trim();
  if (normalizedPageId === "home" && ["hero", "quickmenu", "product-list", "banner", "banner-list", "editorial-product", "service-card"].includes(kind)) {
    return "replace-markup";
  }
  if (["navigation", "controls"].includes(kind)) return "patch-or-replace";
  if (["gallery", "product-list", "banner", "editorial", "editorial-list", "editorial-grid", "service-card"].includes(kind)) {
    return "replace-markup";
  }
  if (Array.isArray(mediaSpec?.notes) && mediaSpec.notes.length) return "patch-or-replace";
  return "patch-only";
}

function buildShareSectionRegistry(pageId, options = {}) {
  const editableData = options.editableData || null;
  const viewportProfile = String(options.viewportProfile || "").trim();
  const normalizedPageId = String(pageId || "").trim();
  const normalizedViewport =
    normalizedPageId === "home"
      ? normalizeHomeViewportProfile(viewportProfile || "pc", "pc")
      : normalizeViewportProfile(viewportProfile || "pc", "pc");
  const cacheKey = buildWorkspacePageCacheKey(editableData || {}, normalizedPageId, "share-section-registry", normalizedViewport);
  return readCachedValue(WORKING_SHARE_SECTION_REGISTRY_CACHE, cacheKey, () => {
    const inventory = buildWorkingComponentInventory(normalizedPageId, { editableData, viewportProfile: normalizedViewport });
    const editableCatalog = buildWorkingEditableComponentCatalog(normalizedPageId, { editableData, viewportProfile: normalizedViewport });
    const editableMap = new Map((editableCatalog.components || []).map((item) => [String(item.componentId || "").trim(), item]));
    const sections = (inventory.components || []).map((component) => {
      const componentId = String(component.componentId || "").trim();
      const slotId = String(component.slotId || "").trim();
      const editable = editableMap.get(componentId) || {};
      const mediaSpec = buildComponentMediaSpec(normalizedPageId, slotId, {
        ...component,
        viewportProfile: normalizedViewport,
      });
      const patchBridge = editable.patchBridge || buildComponentPatchBridge(normalizedPageId, slotId, {
        ...component,
        viewportProfile: normalizedViewport,
      });
      const patchSchema = editable.patchSchema || getGenericPatchSchema(normalizedPageId, slotId);
      const { sectionRect, contentRect } = buildShareSectionRects(normalizedPageId, component, mediaSpec, normalizedViewport);
      return {
        sectionId: `${normalizedPageId}:${normalizedViewport}:${slotId}`,
        pageId: normalizedPageId,
        viewportProfile: normalizedViewport,
        componentId,
        slotId,
        sectionLabel: buildShareSectionLabel(slotId, normalizedPageId),
        sectionType: String(patchBridge.archetype || component.kind || "section").trim() || "section",
        sourceKind: component.activeSourceType || component.renderMode || component.sourceResolution || "working",
        activeSourceId: component.activeSourceId || null,
        resolvedRenderSourceId: component.resolvedRenderSourceId || component.activeSourceId || null,
        containerMode: component.containerMode || mediaSpec.containerMode || null,
        sectionRect,
        contentRect,
        imageZones: buildShareImageZones(normalizedPageId, slotId, component, mediaSpec, normalizedViewport),
        textScale: {
          titleFontSize: mediaSpec?.measuredScale?.titleFontSize || null,
          titleLineHeight: mediaSpec?.measuredScale?.titleLineHeight || null,
        },
        measuredScale: mediaSpec?.measuredScale || null,
        replacementMode: inferShareReplacementMode(normalizedPageId, component, patchBridge, mediaSpec),
        allowedFields: {
          rootKeys: Array.isArray(patchSchema.rootKeys) ? patchSchema.rootKeys : [],
          styleKeys: Array.isArray(patchSchema.styleKeys) ? patchSchema.styleKeys : [],
          editableProps: Array.isArray(editable.editableProps) ? editable.editableProps : [],
          editableStyles: Array.isArray(editable.editableStyles) ? editable.editableStyles : [],
        },
        patchBridge,
        mediaSpec,
        notes: [
          ...(Array.isArray(patchBridge?.structureNotes) ? patchBridge.structureNotes : []),
          ...(Array.isArray(mediaSpec?.notes) ? mediaSpec.notes : []),
        ].slice(0, 4),
      };
    });
    return {
      pageId: normalizedPageId,
      viewportProfile: normalizedViewport,
      source: "working",
      sectionCount: sections.length,
      sections,
    };
  });
}

function analyzeArtifactSectionMarkup(markup = "") {
  const source = String(markup || "");
  if (!source) {
    return {
      className: "",
      dataArea: "",
      imageCount: 0,
      linkCount: 0,
      hasSwiper: false,
      textLength: 0,
    };
  }
  const classMatch = source.match(/<[a-zA-Z][\w:-]*[^>]*class="([^"]+)"/i);
  const dataAreaMatch = source.match(/\sdata-area="([^"]+)"/i);
  const textLength = stripHtml(source).replace(/\s+/g, " ").trim().length;
  return {
    className: classMatch ? classMatch[1] : "",
    dataArea: dataAreaMatch ? dataAreaMatch[1] : "",
    imageCount: (source.match(/<img\b/gi) || []).length,
    linkCount: (source.match(/<a\b/gi) || []).length,
    hasSwiper: /swiper/i.test(source),
    textLength,
  };
}

function buildArtifactSectionSelectorHints(pageId, slotId, viewportProfile = "pc") {
  const normalizedPageId = String(pageId || "").trim();
  const normalizedSlotId = String(slotId || "").trim();
  if (normalizedPageId === "home") {
    const profile = getHomeDesktopRenderProfile(normalizedSlotId) || {};
    const hints = [];
    if (Array.isArray(profile.liveClassFragments) && profile.liveClassFragments.length) {
      hints.push(...profile.liveClassFragments);
    }
    if (profile.dataArea) hints.push(`data-area=${profile.dataArea}`);
    return hints;
  }
  const group = findArtifactGroupForSlot(normalizedPageId, normalizedSlotId, viewportProfile, "reference");
  const hints = [];
  if (group?.selector) hints.push(String(group.selector));
  if (group?.groupId && String(group.groupId) !== normalizedSlotId) hints.push(`groupId=${group.groupId}`);
  hints.push(...getArtifactFallbackSelectors(normalizedPageId, normalizedSlotId, viewportProfile));
  return hints;
}

function readArtifactReferenceHtml(pageId, viewportProfile = "pc") {
  const normalizedPageId = String(pageId || "").trim();
  if (!normalizedPageId) return "";
  if (normalizedPageId === "home") {
    return readReferenceSourceHtmlByPageId(normalizedPageId, viewportProfile) || "";
  }
  if (isPdpCasePageId(normalizedPageId)) {
    return readPageReferenceLiveHtml(normalizedPageId, viewportProfile) || readReferenceSourceHtmlByPageId(normalizedPageId, viewportProfile) || "";
  }
  return readReferenceSourceHtmlByPageId(normalizedPageId, viewportProfile) || "";
}

function findArtifactGroupEntry(pageId, viewportProfile = "pc", sourceType = "reference") {
  const normalizedPageId = String(pageId || "").trim();
  const normalizedViewport = normalizeViewportProfile(viewportProfile, "pc");
  if (isServiceLikePageId(normalizedPageId)) {
    return resolveServiceGroupEntry(normalizedPageId, normalizedViewport, sourceType);
  }
  if (normalizedPageId.startsWith("category-")) {
    const entry = findPlpGroupEntry(normalizedPageId, normalizedViewport, sourceType);
    return entry ? { ...entry, groups: normalizeGroupMap(entry.groups) } : null;
  }
  if (isPdpCasePageId(normalizedPageId)) {
    const pdpContext = resolvePdpRuntimeContext(normalizedPageId);
    const runtimePageId = pdpContext?.runtimePageId || normalizedPageId;
    const href = pdpContext?.href || "";
    const entry =
      findPdpGroupEntry(runtimePageId, normalizedViewport, href, sourceType) ||
      findPdpGroupEntry(runtimePageId, normalizedViewport === "pc" ? "mo" : "pc", href, sourceType);
    return entry ? { ...entry, groups: normalizeGroupMap(entry.groups) } : null;
  }
  return null;
}

function findArtifactGroupForSlot(pageId, slotId, viewportProfile = "pc", sourceType = "reference") {
  const entry = findArtifactGroupEntry(pageId, viewportProfile, sourceType);
  const groups = normalizeGroupMap(entry?.groups);
  return groups[String(slotId || "").trim()] || null;
}

function simplifyGroupRect(group = null) {
  const rect = group?.rect;
  if (!rect || typeof rect !== "object") return null;
  const width = Number(rect.width || 0);
  const height = Number(rect.height || 0);
  if (!width || !height) return null;
  return {
    x: Number(rect.x || 0),
    y: Number(rect.y || 0),
    width,
    height,
  };
}

function estimateArtifactFallbackHeight(pageId = "", slotId = "", markup = "", viewportProfile = "pc") {
  const normalizedPageId = String(pageId || "").trim();
  const normalizedSlotId = String(slotId || "").trim();
  const normalizedViewport =
    normalizedPageId === "home"
      ? normalizeHomeViewportProfile(viewportProfile, "pc")
      : normalizeViewportProfile(viewportProfile, "pc");
  const baseHeightMap = {
    "header-top": 64,
    "header-bottom": 84,
    hero: normalizedViewport === "ta" ? 420 : 500,
    quickmenu: 118,
    "md-choice": 420,
    timedeal: 428,
    "best-ranking": 620,
    "marketing-area": 340,
    subscription: 520,
    "space-renewal": 540,
    "brand-showroom": 500,
    "latest-product-news": 520,
    "smart-life": 500,
    "summary-banner-2": 220,
    "missed-benefits": 340,
    "lg-best-care": 360,
    "bestshop-guide": 220,
    filter: 96,
    sort: 72,
    productGrid: 720,
    firstRow: 370,
    firstProduct: 370,
    banner: 240,
    summary: 420,
    price: 220,
    option: 360,
    sticky: 120,
    review: 960,
    qna: 1080,
    gallery: 720,
  };
  const source = String(markup || "");
  const listCount =
    countMarkupMatches(source, /<li\b/gi) ||
    countMarkupMatches(source, /accordion-item|faq-item|review-item|qna-item|product-card|product-item|swiper-slide/gi);
  const imageCount = countMarkupMatches(source, /<img\b/gi);
  const textLength = stripHtml(source).replace(/\s+/g, " ").trim().length;
  const baseHeight = Number(baseHeightMap[normalizedSlotId] || (normalizedPageId === "home" ? 320 : 280)) || 280;
  return Math.max(
    baseHeight,
    Math.min(2200, baseHeight + listCount * 24 + imageCount * 40 + Math.round(textLength / 12))
  );
}

function buildContractFallbackRect(pageId = "", slotId = "", shareSection = {}, markup = "", viewportProfile = "pc") {
  const sectionRect = shareSection?.sectionRect && typeof shareSection.sectionRect === "object" ? shareSection.sectionRect : null;
  const contentRect = shareSection?.contentRect && typeof shareSection.contentRect === "object" ? shareSection.contentRect : null;
  const useSectionRect = ["header-top", "header-bottom", "hero", "summary-banner-2", "banner"].includes(String(slotId || "").trim());
  const rect = useSectionRect ? (sectionRect || contentRect) : (contentRect || sectionRect);
  const width = Number(rect?.width || 0);
  if (!width) return null;
  const left = Number(rect?.left || 0);
  return {
    x: left,
    y: 0,
    width,
    height: estimateArtifactFallbackHeight(pageId, slotId, markup, viewportProfile),
  };
}

function getArtifactFallbackSelectors(pageId, slotId, viewportProfile = "pc") {
  const normalizedPageId = String(pageId || "").trim();
  const normalizedSlotId = String(slotId || "").trim();
  if (normalizedPageId === "bestshop" && normalizedSlotId === "brandBanner") {
    return [".nav-brand-gate", ".brand-link", ".brand-banner", ".sidemenu_banner"];
  }
  if (normalizedPageId.startsWith("category-")) {
    const plpFallbacks = {
      filter: [
        '[class*="PlpPcFilterTotal_filter__"]',
        '[class*="filter"]',
        '[id*="filter"]',
        '[id^="chk_product_"]',
      ],
      sort: [
        '[class*="PlpPcToolbar_filter_select__"]',
        '[class*="sort"]',
        '[id*="sort"]',
        '[class*="orderby"]',
      ],
      productGrid: [
        '[class*="CommonPcListUnitProduct_list_unit_product__"]',
        '[class*="product-list"]',
        '[class*="productList"]',
        '[class*="list-wrap"]',
        '[class*="list_wrap"]',
        '[class*="plp-list"]',
        '[class*="product-card-title_product-card-title__"]',
      ],
      firstRow: [
        '[class*="CommonPcListUnitProduct_list_unit_product__"]',
        'representativeProducts',
        '[class*="product-list"]',
        '[class*="productList"]',
        '[class*="list-wrap"]',
        '[class*="list_wrap"]',
      ],
      firstProduct: [
        '[class*="product-card-title_product-card-title__"]',
        '[class*="product-card-price_product-card-price__"]',
        '[class*="CommonPcListUnitProduct_unit_product_cta_rs__"]',
        'li[class*="item"]',
        '[class*="product-item"]',
        '[class*="item-card"]',
      ],
      banner: ['[data-area*="구매가이드"]'],
    };
    return plpFallbacks[normalizedSlotId] || [];
  }
  if (isPdpCasePageId(normalizedPageId)) {
    const isMobile = normalizeViewportProfile(viewportProfile, "pc") === "mo";
    const pdpFallbacks = {
      gallery: isMobile
        ? ['#mobile_summary_gallery', '#desktop_summary_gallery', '.pdp-visual-area', '[id*="summary_gallery"]']
        : ['#desktop_summary_gallery', '#mobile_summary_gallery', '.pdp-visual-area', '[id*="summary_gallery"]'],
      summary: ['.pdp-info-area', '[class*="pdp-info-area"]', '[class*="product-info"]'],
      price: ['#b2cPriceArea', '#memberPrice', '#timeDealPrice', '#couponPrice', '#benefitPrice', '[class*="price-detail"]', '[class*="price"]', '[id*="price"]', '[class*="benefit"]'],
      option: ['#productDetailOptionArea', '#abnormalDetailOptionArea', '[class*="product-detail-option"]', '[class*="sibling-option"]', '[class*="sibling-select"]', '[class*="option"]', '[id*="option"]', '[class*="select"]', '[class*="model"]'],
      sticky: ['#countCheckArea', '.box.payment-amount.count-check', '.purchase-button.default', '.purchase-button', '[class*="sticky"]', '[id*="sticky"]', '[class*="purchase"]', '[class*="buy"]', '[class*="cart"]', '[class*="cta"]'],
      review: ['#pdp_review', '.review-info', '[class*="purchase-info-wrap"]', '[class*="option-wrap"]', '#review', '[id*="review"]', '[class*="review"]'],
      qna: ['#pdp_qna', '.component-wrap.full.show', '[class*="ui_accordion"]', '#qna', '[id*="qna"]', '[class*="qna"]'],
    };
    return pdpFallbacks[normalizedSlotId] || [];
  }
  return [];
}

function extractHomeArtifactSectionMarkup(slotId, viewportProfile = "pc") {
  const normalizedSlotId = String(slotId || "").trim();
  const normalizedViewport = normalizeHomeViewportProfile(viewportProfile, "pc");
  if (!normalizedSlotId) return "";
  if (normalizedSlotId === "header-top") {
    return extractCurrentLiveHomeSectionByClass("CommonPcGnb_top__");
  }
  if (normalizedSlotId === "header-bottom") {
    return extractCurrentLiveHomeSectionByClass("CommonPcGnb_bottom__");
  }
  if (normalizedViewport === "mo") {
    const mobileHtml = readHomeMobileHtml() || "";
    if (normalizedSlotId === "hero") return extractMobileHeroSection(mobileHtml);
    if (normalizedSlotId === "quickmenu") return extractMobileQuickMenuSection(mobileHtml);
    if (normalizedSlotId === "timedeal") return extractMobileTimedealSection(mobileHtml);
    if (normalizedSlotId === "space-renewal") return extractMobileSpaceRenewalSection(mobileHtml);
    if (normalizedSlotId === "brand-showroom") return extractMobileBrandShowroomSection(mobileHtml);
    if (normalizedSlotId === "latest-product-news") return extractMobileLatestProductNewsSection(mobileHtml);
    if (normalizedSlotId === "smart-life") return extractMobileSmartLifeSection(mobileHtml);
    if (normalizedSlotId === "missed-benefits") return extractMobileMissedBenefitsSection(mobileHtml);
    if (normalizedSlotId === "lg-best-care") return extractMobileLgBestCareSection(mobileHtml);
    if (normalizedSlotId === "bestshop-guide") return extractMobileBestshopGuideSection(mobileHtml);
    if (normalizedSlotId === "promotion") return extractMobilePromotionSection(mobileHtml);
    if (normalizedSlotId === "summary-banner-2") return extractMobileLowerPromotionSection(mobileHtml);
    return "";
  }
  if (normalizedSlotId === "hero") {
    return (
      extractCurrentLiveHomeSectionByClass("HomePcBannerHero_banner_hero__") ||
      extractCurrentLiveHomeSectionByClass("HomeTaBannerHero_banner_hero__") ||
      extractHomeHeroSection(readHomeDesktopHtml() || "")
    );
  }
  if (normalizedSlotId === "promotion") {
    return extractCurrentLiveHomeSectionByClass("HomePcBannerPromotion_banner_promotion__", "메인 상단 배너 영역");
  }
  return extractCurrentLiveHomeSectionByProfile(normalizedSlotId);
}

function isGenericArtifactSelector(selector = "") {
  const text = String(selector || "").trim();
  if (!text) return false;
  return /\[(id|class)\*=/.test(text) || /\[(id|class)\^=/.test(text);
}

function shouldPreferFallbackArtifactSelectors(pageId = "", slotId = "") {
  const normalizedPageId = String(pageId || "").trim();
  const normalizedSlotId = String(slotId || "").trim();
  if (normalizedPageId.startsWith("category-")) return true;
  if (isPdpCasePageId(normalizedPageId) && ["price", "option", "sticky", "review", "qna"].includes(normalizedSlotId)) {
    return true;
  }
  return false;
}

function extractArtifactSectionMarkup(pageId, slotId, viewportProfile = "pc") {
  const normalizedPageId = String(pageId || "").trim();
  if (normalizedPageId === "home") {
    return extractHomeArtifactSectionMarkup(slotId, viewportProfile);
  }
  const html = readArtifactReferenceHtml(normalizedPageId, viewportProfile);
  if (!html) return "";
  const group = findArtifactGroupForSlot(normalizedPageId, slotId, viewportProfile, "reference");
  const selectors = [];
  const groupSelector = group?.found && group?.selector ? String(group.selector) : "";
  const fallbackSelectors = getArtifactFallbackSelectors(normalizedPageId, slotId, viewportProfile);
  const preferFallbackFirst = shouldPreferFallbackArtifactSelectors(normalizedPageId, slotId);
  if (groupSelector) {
    if (preferFallbackFirst || isGenericArtifactSelector(groupSelector)) {
      selectors.push(...fallbackSelectors, groupSelector);
    } else {
      selectors.push(groupSelector, ...fallbackSelectors);
    }
  } else {
    selectors.push(...fallbackSelectors);
  }
  const orderedSelectors = uniqueNonEmptyLines(selectors);
  for (const selector of orderedSelectors) {
    const markup = extractFirstSelectorBlock(html, selector);
    if (markup) return markup;
  }
  return "";
}

function buildArtifactSectionRegistry(pageId, options = {}) {
  const normalizedPageId = String(pageId || "").trim();
  const normalizedViewport =
    normalizedPageId === "home"
      ? normalizeHomeViewportProfile(options.viewportProfile || "pc", "pc")
      : normalizeViewportProfile(options.viewportProfile || "pc", "pc");
  const editableData = options.editableData || null;
  const workingRegistry = buildShareSectionRegistry(normalizedPageId, {
    editableData,
    viewportProfile: normalizedViewport,
  });
  const sections = (workingRegistry.sections || []).map((section) => {
    const markup = extractArtifactSectionMarkup(normalizedPageId, section.slotId, normalizedViewport);
    const analysis = analyzeArtifactSectionMarkup(markup);
    const extractStatus = markup
      ? "exact-reference-section"
      : section.replacementMode === "replace-markup"
        ? "missing-reference-section"
        : "reference-derived-fallback";
    return {
      ...section,
      source: "reference-artifact",
      extractStatus,
      artifactOrigin: markup ? "lge-reference" : "working-fallback",
      selectorHints: buildArtifactSectionSelectorHints(normalizedPageId, section.slotId, normalizedViewport),
      referenceSection: {
        available: Boolean(markup),
        className: analysis.className || null,
        dataArea: analysis.dataArea || null,
        imageCount: analysis.imageCount,
        linkCount: analysis.linkCount,
        hasSwiper: analysis.hasSwiper,
        textLength: analysis.textLength,
        markupPreview: markup ? markup.slice(0, 1200) : "",
      },
    };
  });
  return {
    pageId: normalizedPageId,
    viewportProfile: normalizedViewport,
    source: "reference-artifact",
    sectionCount: sections.length,
    sections,
  };
}

function simplifyMeasurementRect(slot = null) {
  if (!slot || typeof slot !== "object") return null;
  const width = Number(slot.width || 0);
  const height = Number(slot.height || 0);
  if (!width || !height) return null;
  return {
    x: Number(slot.x || 0),
    y: Number(slot.y || 0),
    width,
    height,
  };
}

function summarizeMeasurementItems(slot = null, limit = 12) {
  const seen = new Set();
  return safeArray(slot?.items || [], 60)
    .map((item) => String(item?.label || "").replace(/\s+/g, " ").trim())
    .filter(Boolean)
    .filter((label) => {
      if (seen.has(label)) return false;
      seen.add(label);
      return true;
    })
    .slice(0, limit);
}

function inferMeasurementImageZones(slot = null) {
  return safeArray(slot?.items || [], 40)
    .filter((item) => /image|img|thumb|media|poster/i.test(String(item?.label || "")))
    .map((item, index) => ({
      id: `${String(slot?.slotId || "section").trim() || "section"}:measured-image-${index + 1}`,
      x: Number(item.x || 0),
      y: Number(item.y || 0),
      width: Number(item.width || 0),
      height: Number(item.height || 0),
      source: "measurement",
    }))
    .filter((item) => item.width > 0 && item.height > 0)
    .slice(0, 8);
}

function countMarkupMatches(markup = "", pattern) {
  const source = String(markup || "");
  if (!source || !pattern) return 0;
  const matches = source.match(pattern);
  return Array.isArray(matches) ? matches.length : 0;
}

function estimateRegionItemCount(slotId = "", markup = "", measurement = null, itemCountHint = 0) {
  const normalizedSlotId = String(slotId || "").trim();
  const labels = summarizeMeasurementItems(measurement, 40);
  const hint = Math.max(0, Number(itemCountHint || 0));
  if (normalizedSlotId === "quickmenu") {
    return labels.filter(Boolean).length || countMarkupMatches(markup, /<a\b/gi) || hint || 0;
  }
  if (normalizedSlotId === "gallery") {
    return countMarkupMatches(markup, /swiper-slide|thumbnail|thumb/gi) || countMarkupMatches(markup, /<li\b/gi) || hint || 0;
  }
  if (normalizedSlotId === "productGrid" || normalizedSlotId === "firstRow" || normalizedSlotId === "firstProduct") {
    const productCardCount = countMarkupMatches(markup, /product-card-title_product-card-title__|product-card-price_product-card-price__|CommonPcListUnitProduct_unit_product_cta_rs__/gi);
    return (
      countMarkupMatches(markup, /<li\b/gi) ||
      productCardCount ||
      countMarkupMatches(markup, /product-item|item-card|product-card|prd-item|product__item/gi) ||
      (normalizedSlotId === "firstProduct" && markup ? 1 : 0) ||
      hint ||
      0
    );
  }
  if (normalizedSlotId === "review" || normalizedSlotId === "qna") {
    const reviewCardCount = countMarkupMatches(markup, /purchase-info-wrap|option-wrap|review-item|qna-item|accordion-item|faq-item/gi);
    const iframeCount = countMarkupMatches(markup, /<iframe\b/gi);
    const iframeHeights = Array.from(String(markup || "").matchAll(/height:\s*([0-9.]+)px/gi))
      .map((match) => Number(match[1] || 0))
      .filter((value) => Number.isFinite(value) && value > 0);
    const iframeDerivedCount = iframeCount
      ? Math.max(
          iframeCount,
          ...iframeHeights.map((value) => Math.max(1, Math.round(value / 280)))
        )
      : 0;
    return (
      countMarkupMatches(markup, /<li\b/gi) ||
      reviewCardCount ||
      iframeDerivedCount ||
      countMarkupMatches(markup, /review-item|qna-item|accordion-item|faq-item|review__item|qna__item/gi) ||
      countMarkupMatches(markup, /<button\b|<dt\b|<dd\b/gi) ||
      hint ||
      0
    );
  }
  return hint || 0;
}

function buildSidecarRepeaterItems(slotId = "", itemKind = "item", itemCount = 0, labels = [], editableFields = []) {
  const normalizedSlotId = String(slotId || "").trim() || "section";
  const count = Math.max(0, Number(itemCount || 0));
  const safeLabels = safeArray(labels || [], Math.max(4, count || 0)).map((item) => String(item || "").trim());
  return Array.from({ length: Math.min(count || safeLabels.length, 16) }, (_, index) => ({
    itemId: `${normalizedSlotId}.${itemKind}.${index + 1}`,
    itemIndex: index,
    label: safeLabels[index] || `${itemKind} ${index + 1}`,
    editableFields: safeArray(editableFields || [], 8),
    layoutScope: "repeater-item",
  }));
}

function buildSidecarNodeBlueprints(regionId = "", fields = [], labels = []) {
  const safeFields = safeArray(fields || [], 10);
  const safeLabels = safeArray(labels || [], 10);
  return safeFields.map((field, index) => ({
    nodeId: `${regionId}.${field}`,
    field,
    label: safeLabels[index] || field,
    editable: true,
  }));
}

function buildSidecarLayoutGovernance(pageId = "", slotId = "", sectionType = "", component = {}, shareSection = {}, editable = {}) {
  const normalizedPageId = String(pageId || "").trim();
  const normalizedSlotId = String(slotId || "").trim();
  const normalizedSectionType = String(sectionType || component.kind || "").trim();
  const base = {
    layoutScope: "container",
    resizePolicy: "container-only",
    widthPolicy: "follow-parent-container",
    itemConsistency: "n/a",
    alignmentPolicy: ["preserve-parent-grid"],
    forbiddenMoves: [
      "independent-width-expansion",
      "independent-overflow-outside-container",
      "absolute-overlay-replacement",
    ],
  };

  if (normalizedSlotId === "quickmenu" || normalizedSectionType === "icon-grid") {
    return {
      ...base,
      layoutScope: "repeater-container",
      resizePolicy: "uniform-items-only",
      widthPolicy: "container-only",
      itemConsistency: "shared-item-size",
      alignmentPolicy: ["shared-row-height", "shared-column-width", "preserve-parent-grid"],
      forbiddenMoves: [
        "single-item-width-change",
        "single-item-height-change",
        "break-parent-grid",
        "independent-overflow-outside-container",
      ],
    };
  }

  if (["productGrid", "firstRow", "firstProduct"].includes(normalizedSlotId) || normalizedSectionType === "product-list") {
    return {
      ...base,
      layoutScope: "grid-container",
      resizePolicy: "uniform-items-only",
      widthPolicy: "container-only",
      itemConsistency: "shared-card-rhythm",
      alignmentPolicy: ["shared-column-width", "shared-row-gap", "preserve-grid-rhythm"],
      forbiddenMoves: [
        "single-card-width-change",
        "single-card-height-change",
        "break-parent-grid",
      ],
    };
  }

  if (normalizedSlotId === "gallery") {
    return {
      ...base,
      layoutScope: "section-group",
      resizePolicy: "group-only",
      widthPolicy: "follow-parent-column",
      itemConsistency: "thumbnail-rail-uniform",
      alignmentPolicy: ["main-and-thumbnail-sync", "preserve-media-ratio"],
      forbiddenMoves: [
        "independent-main-media-width-change",
        "break-thumbnail-rail",
        "replace-sticky-neighbor-layout",
      ],
    };
  }

  if (["summary", "price", "option", "sticky"].includes(normalizedSlotId)) {
    return {
      ...base,
      layoutScope: "column-group",
      resizePolicy: "container-only",
      widthPolicy: "follow-parent-column",
      itemConsistency: "shared-column-width",
      alignmentPolicy: ["shared-column-width", "shared-stack-rhythm"],
      forbiddenMoves: [
        "break-parent-column",
        "independent-width-expansion",
        "single-control-protrusion",
      ],
    };
  }

  if (normalizedSlotId === "review" || normalizedSlotId === "qna") {
    return {
      ...base,
      layoutScope: "content-list",
      resizePolicy: "container-only",
      widthPolicy: "follow-content-width",
      itemConsistency: "shared-list-rhythm",
      alignmentPolicy: ["shared-list-spacing", "preserve-content-stack"],
      forbiddenMoves: [
        "single-item-width-change",
        "break-content-stack",
      ],
    };
  }

  if (normalizedPageId === "home" && ["hero", "timedeal", "best-ranking", "subscription", "space-renewal", "brand-showroom", "summary-banner-2", "lg-best-care", "bestshop-guide"].includes(normalizedSlotId)) {
    return {
      ...base,
      layoutScope: "section-container",
      resizePolicy: "container-only",
      widthPolicy: "follow-layout-token",
      itemConsistency: "section-rhythm-first",
      alignmentPolicy: ["preserve-section-shell", "preserve-content-band"],
      forbiddenMoves: [
        "independent-child-width-expansion",
        "break-section-shell",
      ],
    };
  }

  return base;
}

function buildSidecarRegions(pageId = "", slotId = "", sectionType = "", options = {}) {
  const normalizedPageId = String(pageId || "").trim();
  const normalizedSlotId = String(slotId || "").trim();
  const normalizedSectionType = String(sectionType || "").trim();
  const markup = String(options.markup || "");
  const measurement = options.measurement || null;
  const allowedFields = options.allowedFields || {};
  const labels = summarizeMeasurementItems(measurement, 12);
  const layoutGovernance = options.layoutGovernance || null;
  const itemCountHint = Math.max(0, Number(options.itemCountHint || 0));
  const baseEditableFields = safeArray([
    ...(Array.isArray(allowedFields.rootKeys) ? allowedFields.rootKeys : []),
    ...(Array.isArray(allowedFields.editableProps) ? allowedFields.editableProps : []),
  ], 12);

  const sectionRoot = {
    regionId: `${normalizedSlotId || "section"}.root`,
    role: "section-root",
    replaceMode: "patch-fields",
    editableFields: baseEditableFields,
    visibleLabels: labels.slice(0, 4),
    governance: layoutGovernance,
  };

  if (normalizedSlotId === "quickmenu" || normalizedSectionType === "icon-grid") {
    const itemCount = estimateRegionItemCount(normalizedSlotId, markup, measurement, itemCountHint);
    return [
      sectionRoot,
      {
        regionId: `${normalizedSlotId}.items`,
        role: "repeater",
        replaceMode: "patch-fields",
        selectorHints: ["quickmenu-item", "icon-grid-item", "a"],
        editableFields: ["label", "icon", "href", "visibility"],
        repeater: {
          itemCount,
          itemKind: "quickmenu-item",
          uniformItemContract: true,
        },
        items: buildSidecarRepeaterItems(normalizedSlotId, "quickmenu-item", itemCount, labels, ["label", "icon", "href", "visibility"]),
        nodes: buildSidecarNodeBlueprints(`${normalizedSlotId}.items`, ["label", "icon", "href", "visibility"], labels),
        visibleLabels: labels.slice(0, Math.min(itemCount || 10, 10)),
        governance: layoutGovernance,
      },
    ];
  }

  if (normalizedSlotId === "gallery") {
    const itemCount = estimateRegionItemCount(normalizedSlotId, markup, measurement, itemCountHint);
    return [
      sectionRoot,
      {
        regionId: "gallery.main",
        role: "media-primary",
        replaceMode: "patch-fields",
        selectorHints: ["main-gallery", "hero-media", "gallery-main"],
        editableFields: ["image", "imageFit", "background", "frameStyles"],
        nodes: buildSidecarNodeBlueprints("gallery.main", ["image", "imageFit", "background", "frameStyles"]),
        governance: layoutGovernance,
      },
      {
        regionId: "gallery.thumbnails",
        role: "repeater",
        replaceMode: "patch-fields",
        selectorHints: ["gallery-thumbnail", "thumbnail-rail"],
        editableFields: ["image", "selectedState", "visibility"],
        repeater: {
          itemCount,
          itemKind: "thumbnail",
          uniformItemContract: true,
        },
        items: buildSidecarRepeaterItems(normalizedSlotId, "thumbnail", itemCount, labels, ["image", "selectedState", "visibility"]),
        nodes: buildSidecarNodeBlueprints("gallery.thumbnails", ["image", "selectedState", "visibility"]),
        governance: layoutGovernance,
      },
    ];
  }

  if (normalizedSlotId === "summary") {
    return [
      sectionRoot,
      {
        regionId: "summary.title",
        role: "content-block",
        replaceMode: "patch-fields",
        selectorHints: ["title", "headline", "subtitle"],
        editableFields: ["title", "subtitle", "description", "badge"],
        visibleLabels: labels.slice(0, 6),
        nodes: buildSidecarNodeBlueprints("summary.title", ["badge", "title", "subtitle", "description"], labels),
        governance: layoutGovernance,
      },
      {
        regionId: "summary.meta",
        role: "meta-block",
        replaceMode: "patch-fields",
        selectorHints: ["meta", "benefit", "info"],
        editableFields: ["meta", "badge", "styles"],
        nodes: buildSidecarNodeBlueprints("summary.meta", ["meta", "badge", "styles"], labels),
        governance: layoutGovernance,
      },
    ];
  }

  if (normalizedSlotId === "price") {
    return [
      sectionRoot,
      {
        regionId: "price.stack",
        role: "price-block",
        replaceMode: "patch-fields",
        selectorHints: ["price", "benefit", "discount"],
        editableFields: ["price", "benefitPrice", "discountLabel", "badge"],
        nodes: buildSidecarNodeBlueprints("price.stack", ["price", "benefitPrice", "discountLabel", "badge"], labels),
        governance: layoutGovernance,
      },
    ];
  }

  if (normalizedSlotId === "option") {
    return [
      sectionRoot,
      {
        regionId: "option.controls",
        role: "controls",
        replaceMode: "patch-fields",
        selectorHints: ["option-selector", "option-list", "select"],
        editableFields: ["options", "selectedOption", "visibility", "styles"],
        nodes: buildSidecarNodeBlueprints("option.controls", ["options", "selectedOption", "visibility", "styles"], labels),
        governance: layoutGovernance,
      },
      {
        regionId: "option.selectedState",
        role: "selection-summary",
        replaceMode: "patch-fields",
        selectorHints: ["selected-option", "selection-summary", "option-state"],
        editableFields: ["selectedOption", "description", "styles"],
        nodes: buildSidecarNodeBlueprints("option.selectedState", ["selectedOption", "description", "styles"], labels),
        governance: layoutGovernance,
      },
    ];
  }

  if (normalizedSlotId === "sticky") {
    return [
      sectionRoot,
      {
        regionId: "sticky.buybox",
        role: "sticky-buybox",
        replaceMode: "patch-fields",
        selectorHints: ["sticky", "buybox", "cta"],
        editableFields: ["ctaLabel", "price", "badge", "styles"],
        nodes: buildSidecarNodeBlueprints("sticky.buybox", ["badge", "price", "ctaLabel", "styles"], labels),
        governance: layoutGovernance,
      },
    ];
  }

  if (normalizedSlotId === "review" || normalizedSlotId === "qna") {
    return [
      sectionRoot,
      {
        regionId: `${normalizedSlotId}.list`,
        role: "repeater",
        replaceMode: "patch-fields",
        selectorHints: [`${normalizedSlotId}-list`, `${normalizedSlotId}-item`, "accordion-item"],
        editableFields: ["title", "description", "visibility", "styles"],
        repeater: {
          itemCount: estimateRegionItemCount(normalizedSlotId, markup, measurement, itemCountHint),
          itemKind: normalizedSlotId,
          uniformItemContract: true,
        },
        items: buildSidecarRepeaterItems(normalizedSlotId, normalizedSlotId, estimateRegionItemCount(normalizedSlotId, markup, measurement, itemCountHint), labels, ["title", "description", "visibility", "styles"]),
        nodes: buildSidecarNodeBlueprints(`${normalizedSlotId}.list`, ["title", "description", "visibility", "styles"], labels),
        governance: layoutGovernance,
      },
    ];
  }

  if (["productGrid", "firstRow", "firstProduct"].includes(normalizedSlotId)) {
    return [
      sectionRoot,
      {
        regionId: `${normalizedSlotId}.cards`,
        role: "repeater",
        replaceMode: "patch-fields",
        selectorHints: ["product-card", "list-item", "grid-item"],
        editableFields: ["title", "subtitle", "badge", "image", "price", "ctaLabel", "styles"],
        repeater: {
          itemCount: estimateRegionItemCount(normalizedSlotId, markup, measurement, itemCountHint),
          itemKind: "product-card",
          uniformItemContract: true,
        },
        items: buildSidecarRepeaterItems(normalizedSlotId, "product-card", estimateRegionItemCount(normalizedSlotId, markup, measurement, itemCountHint), labels, ["title", "subtitle", "badge", "image", "price", "ctaLabel", "styles"]),
        nodes: buildSidecarNodeBlueprints(`${normalizedSlotId}.cards`, ["title", "subtitle", "badge", "image", "price", "ctaLabel", "styles"], labels),
        governance: layoutGovernance,
      },
    ];
  }

  if (normalizedPageId === "home" && ["hero", "timedeal", "best-ranking", "subscription", "space-renewal", "brand-showroom", "latest-product-news", "smart-life", "summary-banner-2", "missed-benefits", "lg-best-care", "bestshop-guide"].includes(normalizedSlotId)) {
    return [
      sectionRoot,
      {
        regionId: `${normalizedSlotId}.content`,
        role: "content-block",
        replaceMode: "patch-fields",
        selectorHints: ["headline", "body", "cta", "media"],
        editableFields: ["badge", "title", "subtitle", "description", "ctaLabel", "image", "styles"],
        visibleLabels: labels.slice(0, 6),
        nodes: buildSidecarNodeBlueprints(`${normalizedSlotId}.content`, ["badge", "title", "subtitle", "description", "ctaLabel", "image", "styles"], labels),
        governance: layoutGovernance,
      },
    ];
  }

  return [sectionRoot];
}

function pickMeasurementSlotMap(pageId, source = "clone-content") {
  const measurements = readMeasurements(pageId);
  const payload = measurements[source] || null;
  return Object.fromEntries(safeArray(payload?.slots || [], 100).map((slot) => [String(slot?.slotId || "").trim(), slot]).filter(([slotId]) => Boolean(slotId)));
}

function buildArtifactSidecarRegistry(pageId, options = {}) {
  const normalizedPageId = String(pageId || "").trim();
  const viewportProfile =
    normalizedPageId === "home"
      ? normalizeHomeViewportProfile(options.viewportProfile || "pc", "pc")
      : normalizeViewportProfile(options.viewportProfile || "pc", "pc");
  const editableData = options.editableData || null;
  const artifactRegistry = buildArtifactSectionRegistry(normalizedPageId, { editableData, viewportProfile });
  const shareRegistry = buildShareSectionRegistry(normalizedPageId, { editableData, viewportProfile });
  const editablePayload = buildLlmEditableList(normalizedPageId, { editableData, viewportProfile });
  const shareMap = new Map((shareRegistry.sections || []).map((section) => [String(section.sectionId || "").trim(), section]));
  const editableMap = new Map((editablePayload.components || []).map((item) => [String(item.componentId || "").trim(), item]));
  const referenceMeasurementMap = pickMeasurementSlotMap(normalizedPageId, "reference-content");
  const workingMeasurementMap = pickMeasurementSlotMap(normalizedPageId, "clone-content");
  const referenceGroupEntry = findArtifactGroupEntry(normalizedPageId, viewportProfile, "reference");
  const workingGroupEntry = findArtifactGroupEntry(normalizedPageId, viewportProfile, "working");
  const referenceGroupMap = normalizeGroupMap(referenceGroupEntry?.groups);
  const workingGroupMap = normalizeGroupMap(workingGroupEntry?.groups);
  const sections = (artifactRegistry.sections || []).map((section) => {
    const sectionId = String(section.sectionId || "").trim();
    const slotId = String(section.slotId || "").trim();
    const componentId = String(section.componentId || "").trim();
    const shareSection = shareMap.get(sectionId) || section;
    const editable = editableMap.get(componentId) || {};
    const referenceMeasurement = referenceMeasurementMap[slotId] || null;
    const workingMeasurement = workingMeasurementMap[slotId] || null;
    const referenceGroup = referenceGroupMap[slotId] || null;
    const workingGroup = workingGroupMap[slotId] || null;
    const itemCountHint = Math.max(
      0,
      Number(
        workingGroup?.itemCount ||
        referenceGroup?.itemCount ||
        Number(workingGroup?.imageCount || 0) + Number(workingGroup?.linkCount || 0) ||
        Number(referenceGroup?.imageCount || 0) + Number(referenceGroup?.linkCount || 0) ||
        0
      )
    );
    const artifactMarkup = extractArtifactSectionMarkup(normalizedPageId, slotId, viewportProfile);
    const workingRect =
      simplifyMeasurementRect(workingMeasurement) ||
      simplifyGroupRect(workingGroup) ||
      buildContractFallbackRect(normalizedPageId, slotId, shareSection, artifactMarkup, viewportProfile);
    const referenceRect =
      simplifyMeasurementRect(referenceMeasurement) ||
      simplifyGroupRect(referenceGroup) ||
      (workingRect ? { ...workingRect } : null) ||
      buildContractFallbackRect(normalizedPageId, slotId, shareSection, artifactMarkup, viewportProfile);
    const measuredImageZones = inferMeasurementImageZones(workingMeasurement || referenceMeasurement);
    const allowedFields = shareSection.allowedFields || section.allowedFields || null;
    const patchBridge = editable.patchBridge || shareSection.patchBridge || section.patchBridge || null;
    const mediaSpec = editable.mediaSpec || shareSection.mediaSpec || section.mediaSpec || null;
    const layoutGovernance = buildSidecarLayoutGovernance(
      normalizedPageId,
      slotId,
      String(section.sectionType || shareSection.sectionType || editable?.patchBridge?.archetype || "section").trim() || "section",
      editable,
      shareSection,
      { patchBridge, mediaSpec }
    );
    const regions = buildSidecarRegions(normalizedPageId, slotId, String(section.sectionType || shareSection.sectionType || "").trim(), {
      markup: artifactMarkup,
      measurement: workingMeasurement || referenceMeasurement,
      allowedFields,
      layoutGovernance,
      itemCountHint,
    });
    return {
      sectionId,
      pageId: normalizedPageId,
      viewportProfile,
      slotId,
      componentId,
      label: String(section.sectionLabel || shareSection.sectionLabel || slotId || componentId).trim(),
      sectionType: String(section.sectionType || shareSection.sectionType || editable?.patchBridge?.archetype || "section").trim() || "section",
      artifact: {
        source: "artifact-html",
        artifactOrigin: section.artifactOrigin || null,
        extractStatus: section.extractStatus || null,
        selectorHints: Array.isArray(section.selectorHints) ? section.selectorHints : [],
        referenceSection: section.referenceSection || null,
      },
      geometry: {
        plannedSectionRect: shareSection.sectionRect || null,
        plannedContentRect: shareSection.contentRect || null,
        referenceRect,
        workingRect,
      },
      media: {
        imageZones: measuredImageZones.length ? measuredImageZones : (shareSection.imageZones || section.imageZones || []),
        measuredScale: shareSection.measuredScale || section.measuredScale || editable?.mediaSpec?.measuredScale || null,
      },
      text: {
        labels: summarizeMeasurementItems(workingMeasurement || referenceMeasurement),
      },
      regions,
      layoutGovernance,
      editing: {
        replacementMode: shareSection.replacementMode || section.replacementMode || null,
        allowedFields,
        patchBridge,
        mediaSpec,
      },
      sourceFidelity: {
        hasReferenceMarkup: Boolean(section?.referenceSection?.available),
        hasReferenceMeasurement: Boolean(referenceRect),
        hasWorkingMeasurement: Boolean(workingRect),
      },
    };
  });
  return {
    pageId: normalizedPageId,
    viewportProfile,
    source: "artifact+sidecar",
    sectionCount: sections.length,
    sections,
  };
}

function mergeReferenceSlotMatches(referenceAnalyses = []) {
  const slotMap = new Map();
  for (const analysis of referenceAnalyses || []) {
    for (const match of analysis?.slotMatches || []) {
      const slotId = String(match?.slotId || "").trim();
      if (!slotId) continue;
      const score = Number(match?.score || 0);
      const current = slotMap.get(slotId);
      if (!current || score > Number(current.score || 0)) {
        slotMap.set(slotId, {
          slotId,
          confidence: String(match?.confidence || "low"),
          score,
          reasons: Array.isArray(match?.reasons) ? match.reasons.slice(0, 3) : [],
          referenceUrl: analysis?.requestedUrl || analysis?.finalUrl || null,
        });
      }
    }
  }
  return Array.from(slotMap.values()).sort(
    (a, b) => Number(b.score || 0) - Number(a.score || 0) || String(a.slotId).localeCompare(String(b.slotId), "ko")
  );
}

function mergePageIdentityBrief(baseBrief, overrideBrief = {}) {
  const base = baseBrief && typeof baseBrief === "object" ? baseBrief : {};
  const override = overrideBrief && typeof overrideBrief === "object" ? overrideBrief : {};
  const mergeLines = (key) => {
    const next = Array.isArray(override[key]) ? override[key].map((item) => String(item || "").trim()).filter(Boolean) : [];
    if (next.length) return next;
    return Array.isArray(base[key]) ? base[key] : [];
  };
  return {
    role: String(override.role || base.role || "").trim(),
    purpose: String(override.purpose || base.purpose || "").trim(),
    designIntent: String(override.designIntent || base.designIntent || "").trim(),
    mustPreserve: mergeLines("mustPreserve"),
    shouldAvoid: mergeLines("shouldAvoid"),
    visualGuardrails: mergeLines("visualGuardrails"),
  };
}

function buildPlannerPageContext(pageId, viewportProfile, editableData, options = {}) {
  const normalizedPageId = String(pageId || "").trim();
  const page = findPage(editableData || {}, normalizedPageId);
  const pdpContext = resolvePdpRuntimeContext(normalizedPageId);
  const normalizedViewportProfile =
    normalizedPageId === "home"
      ? normalizeHomeViewportProfile(viewportProfile, "pc")
      : normalizeViewportProfile(viewportProfile, "pc");
  const identity = mergePageIdentityBrief(buildPageIdentityBrief(normalizedPageId, {
    pageTitle: pdpContext?.title || page?.title || normalizedPageId,
    pageGroup: String(page?.pageGroup || (pdpContext ? "product-detail" : "other")).trim() || "other",
  }), options.pageIdentityOverride || {});
  return {
    workspacePageId: normalizedPageId,
    runtimePageId: pdpContext?.runtimePageId || normalizedPageId,
    pageLabel: pdpContext?.title || page?.title || normalizedPageId,
    pageGroup: String(page?.pageGroup || (pdpContext ? "product-detail" : "other")).trim() || "other",
    viewportProfile: normalizedViewportProfile,
    viewportLabel:
      normalizedViewportProfile === "mo"
        ? "mobile"
        : normalizedViewportProfile === "ta"
          ? "tablet"
          : "desktop",
    pageIdentity: identity,
  };
}

