function applyHomeHeroPatch(sectionHtml, activeSourceId = "", componentPatch = {}) {
  if (!sectionHtml) return "";
  let next = String(sectionHtml);
  const patch = sanitizeGovernedComponentPatch("home", "hero", componentPatch, { sectionType: "hero" }).patch || {};
  const styles = patch.styles && typeof patch.styles === "object" ? patch.styles : {};
  next = next.replace(/<section([^>]*)>/, (match) => {
    const styleMatch = match.match(/\sstyle="([^"]*)"/);
    const inlineStyle = [styleMatch ? styleMatch[1] : "", buildSectionPatchStyleText(styles, { includeHeight: true, hidden: patch.visibility === false })]
      .filter(Boolean)
      .join(";");
    const cleaned = match.replace(/\sstyle="[^"]*"/, "");
    return cleaned.replace(/>$/, `${inlineStyle ? ` style="${escapeHtml(inlineStyle)}"` : ""}>`);
  });
  const applyPatchToHeroSlide = (slideHtml) => {
    let nextSlide = String(slideHtml || "");
    if (patch.badge) {
      const badgePattern = /<span class="(?:HomePcBannerHero_banner_hero_badge__|HomeTaBannerHero_banner_hero_badge__|HomeMoBannerHero_banner_hero_badge__)[^"]*"[^>]*>[\s\S]*?<\/span>/;
      if (badgePattern.test(nextSlide)) {
        nextSlide = nextSlide.replace(badgePattern, (match) => {
          const opening = match.match(/^<span[^>]*>/)?.[0] || '<span>';
          return `${opening}${escapeHtml(patch.badge)}</span>`;
        });
      } else {
        nextSlide = nextSlide.replace(
          /(<strong class="(?:HomePcBannerHero_banner_hero_headline__|HomeTaBannerHero_banner_hero_headline__|HomeMoBannerHero_banner_hero_headline__)[^"]*"[^>]*>)/,
          `<span class="codex-home-hero-badge" style="display:inline-flex;align-items:center;margin-bottom:10px;font:700 14px/1.3 Arial,sans-serif;color:#111827;">${escapeHtml(patch.badge)}</span>$1`
        );
      }
    }
    if (patch.headline) {
      nextSlide = replaceFirstMatch(
        nextSlide,
        /<strong class="(?:HomePcBannerHero_banner_hero_headline__|HomeTaBannerHero_banner_hero_headline__|HomeMoBannerHero_banner_hero_headline__)[^"]*"[^>]*>[\s\S]*?<\/strong>/,
        (match) => match[0].replace(/>[\s\S]*?</, `>${escapeHtml(patch.headline)}<`)
      );
    }
    if (patch.description) {
      nextSlide = replaceFirstMatch(
        nextSlide,
        /<p class="(?:HomePcBannerHero_banner_hero_description__|HomeTaBannerHero_banner_hero_description__|HomeMoBannerHero_banner_hero_description__)[^"]*"[^>]*>[\s\S]*?<\/p>/,
        (match) => match[0].replace(/>[\s\S]*?</, `>${escapeHtml(patch.description)}<`)
      );
    }
    if (patch.ctaHref) {
      nextSlide = replaceFirstMatch(
        nextSlide,
        /<a class="(?:HomePcBannerHero_banner_hero_item__|HomeTaBannerHero_banner_hero_item__|HomeMoBannerHero_banner_hero_item__)[^"]*"[^>]*href="[^"]*"[^>]*>/,
        (match) => match[0].replace(/href="[^"]*"/, `href="${escapeHtml(patch.ctaHref)}"`)
      );
    }
    if (patch.ctaLabel) {
      nextSlide = replaceFirstMatch(
        nextSlide,
        /<a class="(?:HomePcBannerHero_banner_hero_item__|HomeTaBannerHero_banner_hero_item__|HomeMoBannerHero_banner_hero_item__)[^"]*"[^>]*>[\s\S]*?<\/a>/,
        (match) => match[0].replace(/>[\s\S]*?</, `>${escapeHtml(patch.ctaLabel)}<`)
      );
    }
    return nextSlide;
  };
  if (patch.badge || patch.headline || patch.description || patch.ctaHref || patch.ctaLabel) {
    const activeSlidePattern = /<div class="swiper-slide[^"]*swiper-slide-active[^"]*"[\s\S]*?<\/a><\/div>/;
    if (activeSlidePattern.test(next)) {
      next = next.replace(activeSlidePattern, (match) => applyPatchToHeroSlide(match));
    } else {
      next = next.replace(/<div class="swiper-slide[^"]*"[\s\S]*?<\/a><\/div>/, (match) => applyPatchToHeroSlide(match));
    }
  }
  const titleStyleText = buildTextPatchStyleText(styles, "title");
  const subtitleStyleText = buildTextPatchStyleText(styles, "subtitle") || titleStyleText;
  if (titleStyleText) {
    next = next.replace(
      /<(strong)( class="(?:HomePcBannerHero_banner_hero_headline__|HomeTaBannerHero_banner_hero_headline__|HomeMoBannerHero_banner_hero_headline__)[^"]*")([^>]*)>/g,
      (match, tag, classes, rest) => {
        if (/style="/.test(rest)) {
          return `<${tag}${classes}${rest.replace(/style="([^"]*)"/, (_, value) => ` style="${escapeHtml(`${value};${titleStyleText}`)}"`)}>`;
        }
        return `<${tag}${classes}${rest} style="${escapeHtml(titleStyleText)}">`;
      }
    );
  }
  if (subtitleStyleText) {
    next = next.replace(
      /<(p)( class="(?:HomePcBannerHero_banner_hero_description__|HomeTaBannerHero_banner_hero_description__|HomeMoBannerHero_banner_hero_description__)[^"]*")([^>]*)>/g,
      (match, tag, classes, rest) => {
        if (/style="/.test(rest)) {
          return `<${tag}${classes}${rest.replace(/style="([^"]*)"/, (_, value) => ` style="${escapeHtml(`${value};${subtitleStyleText}`)}"`)}>`;
        }
        return `<${tag}${classes}${rest} style="${escapeHtml(subtitleStyleText)}">`;
      }
    );
  }
  if (activeSourceId === "figma-home-hero-v1") {
    next = next.replace(/data-codex-active-source-id="[^"]*"/, `data-codex-active-source-id="${escapeHtml(activeSourceId)}" data-codex-hero-variant="figma"`);
  }
  return next;
}

function applyHomeLowerSectionPatch(sectionHtml, slotId = "", activeSourceId = "", componentPatch = {}) {
  if (!sectionHtml) return "";
  const patch = sanitizeGovernedComponentPatch("home", slotId, componentPatch).patch || {};
  const styles = patch.styles && typeof patch.styles === "object" ? patch.styles : {};
  let next = String(sectionHtml);
  next = next.replace(
    /<section([^>]*)>/,
    (match) => {
      const styleMatch = match.match(/\sstyle="([^"]*)"/);
      const inlineStyle = [styleMatch ? styleMatch[1] : "", buildSectionPatchStyleText(styles, { hidden: patch.visibility === false })]
        .filter(Boolean)
        .join(";");
      const cleaned = match.replace(/\sstyle="[^"]*"/, "");
      return cleaned.replace(/>$/, `${inlineStyle ? ` style="${escapeHtml(inlineStyle)}"` : ""}>`);
    }
  );
  if (patch.badge) {
    const badgeHtml = `<span class="codex-home-section-badge" style="display:inline-flex;align-items:center;margin-bottom:8px;font:700 13px/1.3 Arial,sans-serif;color:#111827;letter-spacing:-0.01em;">${escapeHtml(patch.badge)}</span>`;
    if (next.includes("codex-home-section-badge")) {
      next = next.replace(/<span class="codex-home-section-badge"[\s\S]*?<\/span>/, badgeHtml);
    } else if (/<div class="[^"]*title-home_title-home__[^"]*"[^>]*>/.test(next)) {
      next = next.replace(/(<div class="[^"]*title-home_title-home__[^"]*"[^>]*>)/, `$1${badgeHtml}`);
    }
  }
  if (patch.title) {
    next = replaceFirstMatch(
      next,
      /<h2 class="[^"]*title-home_title-home_tit__[^"]*"[^>]*>[\s\S]*?<\/h2>/,
      (match) => match[0].replace(/>[\s\S]*?</, `>${escapeHtml(patch.title)}<`)
    );
  }
  if (patch.subtitle) {
    next = replaceFirstMatch(
      next,
      /<span class="[^"]*title-home_title-home_sub_tit__[^"]*"[^>]*>[\s\S]*?<\/span>/,
      (match) => match[0].replace(/>[\s\S]*?</, `>${escapeHtml(patch.subtitle)}<`)
    );
  }
  if (patch.moreLabel) {
    next = replaceFirstTextMatch(
      next,
      [
        /<(?:a|button)\b[^>]*class="[^"]*(?:more|btn-more)[^"]*"[^>]*>[\s\S]*?<\/(?:a|button)>/i,
        /<span\b[^>]*class="[^"]*(?:more)[^"]*"[^>]*>[\s\S]*?<\/span>/i,
      ],
      patch.moreLabel
    );
  }
  const titleStyleText = buildTextPatchStyleText(styles, "title");
  const subtitleStyleText = buildTextPatchStyleText(styles, "subtitle");
  if (titleStyleText) {
    next = next.replace(
      /<h2 class="([^"]*title-home_title-home_tit__[^"]*)"([^>]*)>/g,
      (match, classes, rest) => {
        if (/style="/.test(rest)) {
          return `<h2 class="${classes}"${rest.replace(/style="([^"]*)"/, (_, value) => ` style="${escapeHtml(`${value};${titleStyleText}`)}"`)}>`;
        }
        return `<h2 class="${classes}"${rest} style="${escapeHtml(titleStyleText)}">`;
      }
    );
  }
  if (subtitleStyleText) {
    next = next.replace(
      /<span class="([^"]*title-home_title-home_sub_tit__[^"]*)"([^>]*)>/g,
      (match, classes, rest) => {
        if (/style="/.test(rest)) {
          return `<span class="${classes}"${rest.replace(/style="([^"]*)"/, (_, value) => ` style="${escapeHtml(`${value};${subtitleStyleText}`)}"`)}>`;
        }
        return `<span class="${classes}"${rest} style="${escapeHtml(subtitleStyleText)}">`;
      }
    );
  }
  if (slotId) {
    next = rewriteSectionHrefsForClone(next, "home", "pc");
  }
  if (slotId) {
    next = next.replace(/<section([^>]*)>/, `<section$1 data-codex-patched="true">`);
  }
  return next;
}

function escapeRegExp(value) {
  return String(value || "").replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
}

function parseSelectorMatcher(selector) {
  const normalized = String(selector || "").trim();
  if (!normalized) return null;
  let tagName = "";
  let remainder = normalized;
  const tagMatch = remainder.match(/^[a-zA-Z][\w:-]*/);
  if (tagMatch && ![".", "#", "["].includes(remainder.charAt(0))) {
    tagName = String(tagMatch[0] || "").toLowerCase();
    remainder = remainder.slice(tagMatch[0].length);
  }
  const classNames = [];
  let idName = "";
  const attributeChecks = [];
  while (remainder.startsWith(".")) {
    const classMatch = remainder.match(/^\.([a-zA-Z0-9_-]+)/);
    if (!classMatch) break;
    classNames.push(classMatch[1]);
    remainder = remainder.slice(classMatch[0].length);
  }
  if (remainder.startsWith("#")) {
    const idMatch = remainder.match(/^#([a-zA-Z0-9_-]+)/);
    if (idMatch) {
      idName = idMatch[1];
      remainder = remainder.slice(idMatch[0].length);
    }
  }
  const attrPattern = /^\[([a-zA-Z_:][-a-zA-Z0-9_:.]*)([*^$]?=)"([^"]*)"\]/;
  while (remainder.startsWith("[")) {
    const attrMatch = remainder.match(attrPattern);
    if (!attrMatch) return null;
    attributeChecks.push({
      name: attrMatch[1],
      operator: attrMatch[2] || "",
      value: attrMatch[3] || "",
    });
    remainder = remainder.slice(attrMatch[0].length);
  }
  if (remainder) return null;
  if (!tagName && !classNames.length && !idName && !attributeChecks.length) {
    if (/^[a-zA-Z0-9_-]+$/.test(normalized)) {
      const needle = normalized;
      return (attrs) => String(attrs || "").includes(needle);
    }
    return null;
  }
  return (attrs, nodeTagName = "") => {
    const safeAttrs = String(attrs || "");
    const readAttr = (name) => {
      const match = safeAttrs.match(new RegExp(`\\b${escapeRegExp(name)}="([^"]*)"`, "i"));
      return String(match?.[1] || "");
    };
    if (tagName && String(nodeTagName || "").toLowerCase() !== tagName) return false;
    if (classNames.length) {
      const classes = new Set(readAttr("class").split(/\s+/).filter(Boolean));
      if (!classNames.every((className) => classes.has(className))) return false;
    }
    if (idName && readAttr("id") !== idName) return false;
    for (const check of attributeChecks) {
      const actual = readAttr(check.name);
      if (!actual) return false;
      if (!check.operator || check.operator === "=") {
        if (actual !== check.value) return false;
      } else if (check.operator === "*=") {
        if (!actual.includes(check.value)) return false;
      } else if (check.operator === "^=") {
        if (!actual.startsWith(check.value)) return false;
      } else if (check.operator === "$=") {
        if (!actual.endsWith(check.value)) return false;
      } else {
        return false;
      }
    }
    return true;
  };
}

function findFirstSelectorNodeRange(html, selector) {
  const matcher = parseSelectorMatcher(selector);
  if (!matcher) return null;
  const source = String(html || "");
  const pattern = /<([a-zA-Z][\w:-]*)([^>]*)>/g;
  let match;
  while ((match = pattern.exec(source))) {
    const [openingTag, tagName, attrs] = match;
    if (openingTag.startsWith("</") || openingTag.startsWith("<!") || openingTag.startsWith("<?")) continue;
    if (!matcher(attrs, tagName)) continue;
    return {
      start: match.index,
      end: pattern.lastIndex,
      tagName,
      openingTag,
      attrs,
    };
  }
  return null;
}

function findMatchingClosingTagRange(html, startIndex, tagName) {
  const source = String(html || "");
  const pattern = new RegExp(`<\\/?${escapeRegExp(tagName)}\\b[^>]*>`, "gi");
  pattern.lastIndex = startIndex;
  let depth = 1;
  let match;
  while ((match = pattern.exec(source))) {
    if (match[0].startsWith(`</${tagName}`)) {
      depth -= 1;
      if (depth === 0) {
        return {
          start: match.index,
          end: pattern.lastIndex,
        };
      }
      continue;
    }
    depth += 1;
  }
  return null;
}

function normalizeCssSizeValue(value) {
  if (value == null) return "";
  const raw = String(value).trim();
  if (!raw) return "";
  if (/^-?\d+(?:\.\d+)?$/.test(raw)) return `${raw}px`;
  return raw;
}

function normalizeCssInlineValue(value) {
  const raw = String(value || "").trim();
  if (!raw) return "";
  return raw.replace(/[;\n\r{}]/g, " ").replace(/\s+/g, " ").trim();
}

function buildSectionPatchStyleText(styles = {}, options = {}) {
  const nextStyles = styles && typeof styles === "object" ? styles : {};
  const styleParts = [];
  if (nextStyles.background) styleParts.push(`background:${nextStyles.background}`);
  const radius = normalizeCssSizeValue(nextStyles.radius);
  if (radius) styleParts.push(`border-radius:${radius}`);
  if (options.includeHeight) {
    const height = normalizeCssSizeValue(nextStyles.height);
    if (height) styleParts.push(`min-height:${height}`);
  }
  const minHeight = normalizeCssSizeValue(nextStyles.minHeight);
  if (minHeight) styleParts.push(`min-height:${minHeight}`);
  const borderWidth = normalizeCssSizeValue(nextStyles.borderWidth);
  const borderStyle = String(nextStyles.borderStyle || "").trim();
  const borderColor = String(nextStyles.borderColor || "").trim();
  if (borderWidth) styleParts.push(`border-width:${borderWidth}`);
  if (borderStyle) styleParts.push(`border-style:${borderStyle}`);
  if (borderColor) styleParts.push(`border-color:${borderColor}`);
  if ((borderWidth || borderColor) && !borderStyle) styleParts.push("border-style:solid");
  if (nextStyles.boxShadow) styleParts.push(`box-shadow:${nextStyles.boxShadow}`);
  if (nextStyles.padding) styleParts.push(`padding:${nextStyles.padding}`);
  if (nextStyles.opacity !== undefined && nextStyles.opacity !== null && String(nextStyles.opacity).trim() !== "") {
    const opacity = Number(nextStyles.opacity);
    if (Number.isFinite(opacity)) styleParts.push(`opacity:${opacity}`);
  }
  if (nextStyles.textAlign) styleParts.push(`text-align:${nextStyles.textAlign}`);
  if (options.hidden) styleParts.push("display:none");
  return styleParts.filter(Boolean).join(";");
}

function buildTextPatchStyleText(styles = {}, kind = "title") {
  const nextStyles = styles && typeof styles === "object" ? styles : {};
  const colorKey = kind === "subtitle" ? "subtitleColor" : "titleColor";
  const weightKey = kind === "subtitle" ? "subtitleWeight" : "titleWeight";
  const sizeKey = kind === "subtitle" ? "subtitleSize" : "titleSize";
  const lineHeightKey = kind === "subtitle" ? "subtitleLineHeight" : "titleLineHeight";
  const letterSpacingKey = kind === "subtitle" ? "subtitleLetterSpacing" : "titleLetterSpacing";
  const familyKey = kind === "subtitle" ? "subtitleFontFamily" : "titleFontFamily";
  const transformKey = kind === "subtitle" ? "subtitleTextTransform" : "titleTextTransform";
  const styleKey = kind === "subtitle" ? "subtitleFontStyle" : "titleFontStyle";
  const styleParts = [];
  if (nextStyles[colorKey]) styleParts.push(`color:${nextStyles[colorKey]}`);
  if (nextStyles[weightKey]) styleParts.push(`font-weight:${nextStyles[weightKey]}`);
  const size = normalizeCssSizeValue(nextStyles[sizeKey]);
  if (size) styleParts.push(`font-size:${size}`);
  const lineHeight = normalizeCssSizeValue(nextStyles[lineHeightKey]);
  if (lineHeight) styleParts.push(`line-height:${lineHeight}`);
  const letterSpacing = normalizeCssSizeValue(nextStyles[letterSpacingKey]);
  if (letterSpacing) styleParts.push(`letter-spacing:${letterSpacing}`);
  const fontFamily = normalizeCssInlineValue(nextStyles[familyKey]);
  if (fontFamily) styleParts.push(`font-family:${fontFamily}`);
  const textTransform = normalizeCssInlineValue(nextStyles[transformKey]);
  if (textTransform) styleParts.push(`text-transform:${textTransform}`);
  const fontStyle = normalizeCssInlineValue(nextStyles[styleKey]);
  if (fontStyle) styleParts.push(`font-style:${fontStyle}`);
  if (nextStyles.textAlign) styleParts.push(`text-align:${nextStyles.textAlign}`);
  return styleParts.filter(Boolean).join(";");
}

function upsertOpeningTagAttribute(openingTag, name, value) {
  const safeName = String(name || "").trim();
  if (!safeName) return openingTag;
  const escapedValue = escapeHtml(value);
  const attrPattern = new RegExp(`\\s${escapeRegExp(safeName)}="[^"]*"`, "i");
  if (attrPattern.test(openingTag)) {
    return openingTag.replace(attrPattern, ` ${safeName}="${escapedValue}"`);
  }
  return openingTag.replace(/>$/, ` ${safeName}="${escapedValue}">`);
}

function appendOpeningTagStyle(openingTag, styleText) {
  const nextStyle = String(styleText || "").trim();
  if (!nextStyle) return openingTag;
  const styleMatch = openingTag.match(/\sstyle="([^"]*)"/i);
  if (styleMatch) {
    const merged = [styleMatch[1], nextStyle].filter(Boolean).join(";");
    return openingTag.replace(/\sstyle="([^"]*)"/i, ` style="${escapeHtml(merged)}"`);
  }
  return openingTag.replace(/>$/, ` style="${escapeHtml(nextStyle)}">`);
}

function styleFirstPattern(blockHtml, patterns, styleText) {
  let next = String(blockHtml || "");
  const targetStyle = String(styleText || "").trim();
  if (!targetStyle) return next;
  for (const pattern of patterns) {
    const match = next.match(pattern);
    if (!match) continue;
    const openingTag = match[0];
    const styledTag = /style="/i.test(openingTag)
      ? openingTag.replace(/style="([^"]*)"/i, (_, value) => `style="${escapeHtml(`${value};${targetStyle}`)}"`)
      : openingTag.replace(/>$/, ` style="${escapeHtml(targetStyle)}">`);
    next = next.replace(openingTag, styledTag);
    return next;
  }
  return next;
}

function replaceFirstTextMatch(blockHtml, patterns, value) {
  let next = String(blockHtml || "");
  const target = escapeHtml(value);
  for (const pattern of patterns) {
    if (!pattern.test(next)) continue;
    next = next.replace(pattern, (match) => match.replace(/>[\s\S]*?</, `>${target}<`));
    return next;
  }
  return next;
}

function replaceSequentialTextMatches(blockHtml, pattern, values = []) {
  const queue = Array.isArray(values)
    ? values.map((item) => String(item || "").trim()).filter(Boolean)
    : [];
  if (!queue.length) return String(blockHtml || "");
  let index = 0;
  return String(blockHtml || "").replace(pattern, (match) => {
    const nextValue = queue[index];
    if (!nextValue) return match;
    index += 1;
    return match.replace(/>[\s\S]*?</, `>${escapeHtml(nextValue)}<`);
  });
}

function replaceSequentialAnchorHrefs(blockHtml, pattern, items = []) {
  const queue = Array.isArray(items) ? items : [];
  let index = 0;
  return String(blockHtml || "").replace(pattern, (match) => {
    const item = queue[index];
    index += 1;
    if (!item?.href) return match;
    return match.replace(/href="[^"]*"/, `href="${escapeHtml(String(item.href || ""))}"`);
  });
}

function applyHomeHeaderTopPatch(sectionHtml, activeSourceId = "", componentPatch = {}) {
  if (!sectionHtml) return "";
  const patch = sanitizeGovernedComponentPatch("home", "header-top", componentPatch).patch || {};
  const styles = patch.styles && typeof patch.styles === "object" ? patch.styles : {};
  let next = String(sectionHtml);
  next = next.replace(/<section([^>]*)>/, (match) => {
    const cleaned = match.replace(/\sstyle="[^"]*"/, "");
    const inlineStyle = buildSectionPatchStyleText(styles, { hidden: patch.visibility === false });
    return cleaned.replace(/>$/, `${inlineStyle ? ` style="${escapeHtml(inlineStyle)}"` : ""} data-codex-patched="true">`);
  });
  if (patch.logoHref) {
    next = replaceFirstMatch(
      next,
      /<a\b[^>]*aria-label="LG전자"[^>]*href="[^"]*"[^>]*>/i,
      (match) => match[0].replace(/href="[^"]*"/, `href="${escapeHtml(String(patch.logoHref || ""))}"`)
    );
  }
  if (patch.title || patch.subtitle) {
    const titleStyle = buildTextPatchStyleText(styles, "title");
    const subtitleStyle = buildTextPatchStyleText(styles, "subtitle");
    const introHtml = `
      <div class="codex-home-header-top-intro" style="display:flex;flex-direction:column;gap:4px;min-width:0;flex:1;align-items:flex-start;justify-content:center;padding:0 24px 0 28px;">
        ${patch.title ? `<strong style="display:block;font:700 15px/1.35 Arial,sans-serif;color:#111827;letter-spacing:-0.02em;${titleStyle ? escapeHtml(`;${titleStyle}`) : ""}">${escapeHtml(patch.title)}</strong>` : ""}
        ${patch.subtitle ? `<span style="display:block;font:500 12px/1.45 Arial,sans-serif;color:#4b5563;letter-spacing:-0.01em;${subtitleStyle ? escapeHtml(`;${subtitleStyle}`) : ""}">${escapeHtml(patch.subtitle)}</span>` : ""}
      </div>`;
    if (next.includes("codex-home-header-top-intro")) {
      next = next.replace(/<div class="codex-home-header-top-intro"[\s\S]*?<\/div>/, introHtml);
    } else {
      next = next.replace(/(<h1 class="CommonPcGnb_logo___kjxo">[\s\S]*?<\/h1>)/, `$1${introHtml}`);
    }
  }
  if (Array.isArray(patch.utilityLinks) && patch.utilityLinks.length) {
    next = replaceSequentialTextMatches(
      next,
      /<a\b[^>]*class="link_company"[^>]*>[\s\S]*?<\/a>|<div class="business"><a\b[^>]*>[\s\S]*?<\/a>/g,
      patch.utilityLinks
    );
  }
  return next;
}

function applyHomeHeaderBottomPatch(sectionHtml, activeSourceId = "", componentPatch = {}) {
  if (!sectionHtml) return "";
  const patch = sanitizeGovernedComponentPatch("home", "header-bottom", componentPatch).patch || {};
  const styles = patch.styles && typeof patch.styles === "object" ? patch.styles : {};
  let next = String(sectionHtml);
  next = next.replace(/<section([^>]*)>/, (match) => {
    const cleaned = match.replace(/\sstyle="[^"]*"/, "");
    const inlineStyle = buildSectionPatchStyleText(styles, { hidden: patch.visibility === false });
    return cleaned.replace(/>$/, `${inlineStyle ? ` style="${escapeHtml(inlineStyle)}"` : ""} data-codex-patched="true">`);
  });
  if (patch.title || patch.subtitle) {
    const titleStyle = buildTextPatchStyleText(styles, "title");
    const subtitleStyle = buildTextPatchStyleText(styles, "subtitle");
    const introHtml = `
      <div class="codex-home-header-bottom-intro" style="display:flex;align-items:flex-start;gap:10px;padding:12px 0 10px 2px;flex-wrap:wrap;">
        ${patch.title ? `<strong style="display:block;font:700 14px/1.35 Arial,sans-serif;color:#111827;letter-spacing:-0.02em;${titleStyle ? escapeHtml(`;${titleStyle}`) : ""}">${escapeHtml(patch.title)}</strong>` : ""}
        ${patch.subtitle ? `<span style="display:block;font:500 12px/1.45 Arial,sans-serif;color:#6b7280;letter-spacing:-0.01em;${subtitleStyle ? escapeHtml(`;${subtitleStyle}`) : ""}">${escapeHtml(patch.subtitle)}</span>` : ""}
      </div>`;
    if (next.includes("codex-home-header-bottom-intro")) {
      next = next.replace(/<div class="codex-home-header-bottom-intro"[\s\S]*?<\/div>/, introHtml);
    } else {
      next = next.replace(/(<div class="CommonPcGnb_nav__Ri977">)/, `${introHtml}$1`);
    }
  }
  if (Array.isArray(patch.mainMenus) && patch.mainMenus.length) {
    next = replaceSequentialTextMatches(
      next,
      /<a\b[^>]*class="CommonPcGnb_item__[^"]*"[^>]*>[\s\S]*?<\/a>/g,
      patch.mainMenus
    );
  }
  return next;
}

function applyHomeQuickmenuPatch(sectionHtml, activeSourceId = "", componentPatch = {}, viewportProfile = "pc") {
  if (!sectionHtml) return "";
  const patch = sanitizeGovernedComponentPatch("home", "quickmenu", componentPatch, { sectionType: "icon-grid" }).patch || {};
  const styles = patch.styles && typeof patch.styles === "object" ? patch.styles : {};
  let next = String(sectionHtml);
  const contractStyle = buildHomeSectionContractStyle("quickmenu", viewportProfile);
  next = next.replace(/<section([^>]*)>/, (match) => {
    const cleaned = match.replace(/\sstyle="[^"]*"/, "");
    const inlineStyle = [contractStyle, buildSectionPatchStyleText(styles, { hidden: patch.visibility === false })].filter(Boolean).join(";");
    return cleaned.replace(/>$/, `${inlineStyle ? ` style="${escapeHtml(inlineStyle)}"` : ""} data-codex-patched="true">`);
  });
  if (patch.title || patch.subtitle) {
    const titleStyle = buildTextPatchStyleText(styles, "title");
    const subtitleStyle = buildTextPatchStyleText(styles, "subtitle");
    const headHtml = `
      <div class="codex-home-quickmenu-head" style="max-width:var(--codex-content-width, 1460px);margin:0 auto;padding:8px 24px 16px;">
        ${patch.title ? `<strong style="display:block;font:700 24px/1.28 Arial,sans-serif;color:#111827;letter-spacing:-0.03em;${titleStyle ? escapeHtml(`;${titleStyle}`) : ""}">${escapeHtml(patch.title)}</strong>` : ""}
        ${patch.subtitle ? `<span style="display:block;margin-top:6px;font:500 14px/1.5 Arial,sans-serif;color:#6b7280;letter-spacing:-0.01em;${subtitleStyle ? escapeHtml(`;${subtitleStyle}`) : ""}">${escapeHtml(patch.subtitle)}</span>` : ""}
      </div>`;
    if (next.includes("codex-home-quickmenu-head")) {
      next = next.replace(/<div class="codex-home-quickmenu-head"[\s\S]*?<\/div>/, headHtml);
    } else {
      next = next.replace(/(<div class="carousel_carousel__2JX9H">|<div class="codex-home-shell codex-home-shell--narrow">)/, `${headHtml}$1`);
    }
  }
  if (Array.isArray(patch.items) && patch.items.length) {
    const items = patch.items;
    next = replaceSequentialTextMatches(
      next,
      /<strong class="HomePcQuickmenu_quickmenu_title__[^"]*"[^>]*>[\s\S]*?<\/strong>|<strong>[\s\S]*?<\/strong>/g,
      items.map((item) => item?.title || "")
    );
    next = replaceSequentialAnchorHrefs(
      next,
      /<a\b[^>]*href="[^"]*"[^>]*>/g,
      items
    );
    let imageIndex = 0;
    next = next.replace(/<img\b([^>]*?)alt="([^"]*)"([^>]*?)src="([^"]+)"([^>]*)>/g, (match, before, alt, middle, src, after) => {
      const item = items[imageIndex];
      if (!item) return match;
      imageIndex += 1;
      const nextSrc = String(item.image || item.imageSrc || src || "").trim();
      const nextAlt = String(item.alt || item.title || alt || "").trim();
      let rewritten = `<img${before}alt="${escapeHtml(nextAlt)}"${middle}src="${escapeHtml(nextSrc || src)}"${after}>`;
      return rewritten;
    });
  }
  return next;
}

function applyGenericWorkspaceSectionPatch(sectionHtml, componentPatch = {}, context = {}) {
  if (!sectionHtml) return "";
  const patch = sanitizeGovernedComponentPatch(
    String(context.pageId || "").trim(),
    String(context.slotId || "").trim(),
    componentPatch,
    { sectionType: String(context.sectionType || "").trim() }
  ).patch || {};
  const styles = patch.styles && typeof patch.styles === "object" ? patch.styles : {};
  let next = String(sectionHtml);
  next = next.replace(/<([a-zA-Z][\w:-]*)([^>]*)>/, (match) => {
    let openingTag = match;
    openingTag = appendOpeningTagStyle(
      openingTag,
      buildSectionPatchStyleText(styles, { includeHeight: true, hidden: patch.visibility === false })
    );
    if (Object.keys(patch).length) {
      openingTag = upsertOpeningTagAttribute(openingTag, "data-codex-patched", "true");
    }
    return openingTag;
  });
  if (patch.title) {
    next = replaceFirstTextMatch(
      next,
      [
        /<h[1-6]\b[^>]*>[\s\S]*?<\/h[1-6]>/i,
        /<div\b class="[^"]*(?:section-title|section__title|bestcare-title)[^"]*"[^>]*>[\s\S]*?<\/div>/i,
        /<strong\b class="[^"]*(?:tit|title)[^"]*"[^>]*>[\s\S]*?<\/strong>/i,
      ],
      patch.title
    );
  }
  if (patch.subtitle) {
    next = replaceFirstTextMatch(
      next,
      [
        /<p\b[^>]*>[\s\S]*?<\/p>/i,
        /<div\b class="[^"]*(?:bestcare-description)[^"]*"[^>]*>[\s\S]*?<\/div>/i,
        /<span\b class="[^"]*(?:desc|description)[^"]*"[^>]*>[\s\S]*?<\/span>/i,
      ],
      patch.subtitle
    );
  }
  if (patch.description) {
    next = replaceFirstTextMatch(
      next,
      [
        /<p\b[^>]*>[\s\S]*?<\/p>/i,
        /<div\b class="[^"]*(?:bestcare-description|desc|description)[^"]*"[^>]*>[\s\S]*?<\/div>/i,
        /<span\b class="[^"]*(?:desc|description)[^"]*"[^>]*>[\s\S]*?<\/span>/i,
      ],
      patch.description
    );
  }
  if (patch.badge) {
    next = replaceFirstTextMatch(
      next,
      [
        /<span\b class="[^"]*(?:badge)[^"]*"[^>]*>[\s\S]*?<\/span>/i,
        /<div\b class="[^"]*(?:badge)[^"]*"[^>]*>[\s\S]*?<\/div>/i,
      ],
      patch.badge
    );
  }
  if (patch.moreLabel) {
    next = replaceFirstTextMatch(
      next,
      [
        /<(?:a|button)\b[^>]*class="[^"]*(?:more|btn-more)[^"]*"[^>]*>[\s\S]*?<\/(?:a|button)>/i,
        /<span\b[^>]*class="[^"]*(?:more)[^"]*"[^>]*>[\s\S]*?<\/span>/i,
      ],
      patch.moreLabel
    );
  }
  if (patch.ctaLabel) {
    next = replaceFirstTextMatch(
      next,
      [/<(?:a|button)\b[^>]*>[\s\S]*?<\/(?:a|button)>/i],
      patch.ctaLabel
    );
  }
  if (patch.ctaHref) {
    next = replaceFirstMatch(
      next,
      /<a\b[^>]*href="[^"]*"[^>]*>/i,
      (match) => match[0].replace(/href="[^"]*"/, `href="${escapeHtml(patch.ctaHref)}"`)
    );
  }
  const titleStyleText = buildTextPatchStyleText(styles, "title");
  const subtitleStyleText = buildTextPatchStyleText(styles, "subtitle");
  if (titleStyleText) {
    next = styleFirstPattern(
      next,
      [
        /<((?:h[1-6])\b[^>]*)([^>]*)>/i,
        /<((?:div|strong)\b[^>]*class="[^"]*(?:section-title|section__title|bestcare-title|banner-tit|tit|title)[^"]*"[^>]*)([^>]*)>/i,
      ],
      titleStyleText
    );
  }
  if (subtitleStyleText) {
    next = styleFirstPattern(
      next,
      [
        /<((?:p)\b[^>]*)([^>]*)>/i,
        /<((?:div|span)\b[^>]*class="[^"]*(?:bestcare-description|desc|description)[^"]*"[^>]*)([^>]*)>/i,
      ],
      subtitleStyleText
    );
  }
  return next;
}

function getWorkspaceSlotSourceMeta(data, pageId, slotId) {
  const fallbackSourceId = `captured-${pageId}-${slotId}`;
  const slot = findSlotConfig(data, pageId, slotId);
  const sourceId = getActiveSourceId(data, pageId, slotId, fallbackSourceId);
  const sourceType =
    (slot?.sources || []).find((source) => source.sourceId === sourceId)?.sourceType ||
    (sourceId.startsWith("figma-") ? "figma-derived" : sourceId.startsWith("custom-") ? "custom" : "captured");
  return { sourceId, sourceType };
}

function transformFirstSelectorBlock(html, selector, transform) {
  const source = String(html || "");
  const opening = findFirstSelectorNodeRange(source, selector);
  if (!opening) return source;
  const closing = findMatchingClosingTagRange(source, opening.end, opening.tagName);
  if (!closing) return source;
  const block = source.slice(opening.start, closing.end);
  const nextBlock = typeof transform === "function" ? transform(block, opening) : block;
  return `${source.slice(0, opening.start)}${nextBlock}${source.slice(closing.end)}`;
}

function replaceFirstAvailableSelectorBlock(html, selectors = [], transform) {
  const source = String(html || "");
  const candidates = Array.isArray(selectors)
    ? selectors.map((item) => String(item || "").trim()).filter(Boolean)
    : [];
  for (const selector of candidates) {
    const opening = findFirstSelectorNodeRange(source, selector);
    if (!opening) continue;
    const closing = findMatchingClosingTagRange(source, opening.end, opening.tagName);
    if (!closing) continue;
    const block = source.slice(opening.start, closing.end);
    const nextBlock = typeof transform === "function" ? transform(block, opening, selector) : block;
    return {
      html: `${source.slice(0, opening.start)}${nextBlock}${source.slice(closing.end)}`,
      replaced: String(nextBlock || "") !== block,
      selector,
      block,
    };
  }
  return {
    html: source,
    replaced: false,
    selector: "",
    block: "",
  };
}

function extractFirstSelectorBlock(html, selector) {
  let extracted = "";
  transformFirstSelectorBlock(String(html || ""), selector, (block) => {
    extracted = String(block || "");
    return block;
  });
  return extracted;
}

function buildReplacementSelectorCandidates(pageId = "", slotId = "", selector = "", viewportProfile = "pc") {
  const candidates = [];
  const primarySelector = String(selector || "").trim();
  if (primarySelector) candidates.push(primarySelector);
  for (const fallbackSelector of getArtifactFallbackSelectors(pageId, slotId, viewportProfile)) {
    const normalized = String(fallbackSelector || "").trim();
    if (normalized) candidates.push(normalized);
  }
  return Array.from(new Set(candidates));
}

function hasCodexSlotMarker(html = "", slotId = "") {
  const normalizedSlotId = String(slotId || "").trim();
  if (!normalizedSlotId) return false;
  return new RegExp(`\\bdata-codex-slot="${escapeRegExp(normalizedSlotId)}"`, "i").test(String(html || ""));
}

function extractFirstAvailableSelectorBlock(html = "", selectors = []) {
  for (const selector of Array.isArray(selectors) ? selectors : []) {
    const normalized = String(selector || "").trim();
    if (!normalized) continue;
    const block = extractFirstSelectorBlock(html, normalized);
    if (String(block || "").trim()) return block;
  }
  return "";
}

function appendMarkupBeforeMainClose(html = "", markup = "") {
  const source = String(html || "");
  const addition = String(markup || "").trim();
  if (!addition) return source;
  const closePattern = /<\/main>/i;
  if (!closePattern.test(source)) return `${source}${addition}`;
  return source.replace(closePattern, `${addition}\n</main>`);
}

function applyWorkspacePageVariants(html, pageId, viewportProfile, editableData) {
  let next = String(html || "");
  const normalizedPageId = String(pageId || "").trim();
  if (!normalizedPageId || normalizedPageId === "home") return next;

  const annotateSlot = (slotId, selector) => {
    const sourceMeta = getWorkspaceSlotSourceMeta(editableData || {}, normalizedPageId, slotId);
    const componentId = `${normalizedPageId}.${slotId}`;
    const patchSchema = getGenericPatchSchema(normalizedPageId, slotId);
    const hasPatchSupport = (patchSchema.rootKeys || []).length > 0 || (patchSchema.styleKeys || []).length > 0;
    const patch = hasPatchSupport
      ? findComponentPatch(editableData || {}, normalizedPageId, componentId, sourceMeta.sourceId)?.patch || null
      : null;
    next = transformFirstSelectorBlock(next, selector, (block) => {
      let patched = String(block || "");
      patched = patched.replace(/<([a-zA-Z][\w:-]*)([^>]*)>/, (openingTag) => {
        let result = openingTag;
        result = upsertOpeningTagAttribute(result, "data-codex-slot", slotId);
        result = upsertOpeningTagAttribute(result, "data-codex-source", sourceMeta.sourceType);
        result = upsertOpeningTagAttribute(result, "data-codex-component-id", componentId);
        result = upsertOpeningTagAttribute(result, "data-codex-active-source-id", sourceMeta.sourceId);
        return result;
      });
      if (patch && hasPatchSupport) {
        patched = applyGenericWorkspaceSectionPatch(patched, patch, {
          pageId: normalizedPageId,
          slotId,
          sectionType: "",
        });
      }
      return patched;
    });
  };

  if (isServiceLikePageId(normalizedPageId)) {
    const entry = resolveServiceGroupEntry(normalizedPageId, viewportProfile, "working");
    const groups = normalizeGroupMap(entry?.groups);
    for (const [slotId, group] of Object.entries(groups || {})) {
      if (!group?.found || !group?.selector) continue;
      annotateSlot(slotId, group.selector);
    }
    return next;
  }

  if (normalizedPageId.startsWith("category-")) {
    const entry = findPlpGroupEntry(normalizedPageId, viewportProfile, "working");
    const groups = normalizeGroupMap(entry?.groups);
    for (const [slotId, group] of Object.entries(groups || {})) {
      if (!group?.found || !group?.selector) continue;
      if (!String(group.selector).startsWith(".") && !String(group.selector).startsWith("[")) continue;
      annotateSlot(slotId, group.selector);
    }
  }

  return next;
}

function applyWorkspaceProductVariants(html, pageId, viewportProfile, href, editableData) {
  let next = String(html || "");
  const normalizedPageId = String(pageId || "").trim();
  const normalizedViewportProfile = String(viewportProfile || "pc").trim() || "pc";
  const normalizedHref = String(href || "").trim();
  if (!normalizedPageId || !normalizedHref) return next;

  const pdpContext = resolvePdpRuntimeContext(normalizedPageId, normalizedHref);
  const capturePageId = pdpContext?.runtimePageId || normalizedPageId;
  const captureHref = pdpContext?.href || normalizedHref;
  const entry =
    findPdpGroupEntry(capturePageId, normalizedViewportProfile, captureHref, "reference") ||
    findPdpGroupEntry(capturePageId, normalizedViewportProfile === "pc" ? "mo" : "pc", captureHref, "reference");
  const groups = normalizeGroupMap(entry?.groups);
  if (!Object.keys(groups || {}).length) return next;

  const annotateSlot = (slotId, selector) => {
    if (!selector) return;
    const sourceMeta = getWorkspaceSlotSourceMeta(editableData || {}, normalizedPageId, slotId);
    const componentId = `${normalizedPageId}.${slotId}`;
    const patchSchema = getGenericPatchSchema(normalizedPageId, slotId);
    const hasPatchSupport = (patchSchema.rootKeys || []).length > 0 || (patchSchema.styleKeys || []).length > 0;
    const patch = hasPatchSupport
      ? findComponentPatch(editableData || {}, normalizedPageId, componentId, sourceMeta.sourceId)?.patch || null
      : null;
    next = transformFirstSelectorBlock(next, selector, (block) => {
      let patched = String(block || "");
      patched = patched.replace(/<([a-zA-Z][\w:-]*)([^>]*)>/, (openingTag) => {
        let result = openingTag;
        result = upsertOpeningTagAttribute(result, "data-codex-slot", slotId);
        result = upsertOpeningTagAttribute(result, "data-codex-source", sourceMeta.sourceType);
        result = upsertOpeningTagAttribute(result, "data-codex-component-id", componentId);
        result = upsertOpeningTagAttribute(result, "data-codex-active-source-id", sourceMeta.sourceId);
        return result;
      });
      if (patch && hasPatchSupport) {
        patched = applyGenericWorkspaceSectionPatch(patched, patch, {
          pageId: normalizedPageId,
          slotId,
          sectionType: "",
        });
      }
      return patched;
    });
  };

  for (const [slotId, group] of Object.entries(groups || {})) {
    if (!group?.found || !group?.selector) continue;
    annotateSlot(slotId, group.selector);
  }
  return next;
}

function extractImageQueueAroundMarker(rawHtml, marker, imageField = "mediumImageAddr", windowSize = 60000) {
  const source = String(rawHtml || "");
  const idx = source.indexOf(marker);
  if (idx === -1) return [];
  const snippet = source.slice(idx, Math.min(source.length, idx + windowSize));
  const pattern = new RegExp(`"${imageField}":"([^"]+)"`, "g");
  const queue = [];
  let match;
  while ((match = pattern.exec(snippet))) {
    if (match[1]) {
      queue.push({ image: match[1] });
    }
  }
  return queue;
}

function mergeImageQueues(...queues) {
  return queues.flat().filter((item) => item && item.image);
}

function extractMobileHeroSection(rawHtml) {
  const match = rawHtml.match(/<section class="HomeMoBannerHero_banner_hero__[^"]*"[\s\S]*?<\/section>/);
  return match ? match[0] : "";
}

function extractHomeHeroSection(rawHtml) {
  const match =
    rawHtml.match(/<section class="HomePcBannerHero_banner_hero__[^"]*"[\s\S]*?<\/section>/) ||
    rawHtml.match(/<section class="HomeTaBannerHero_banner_hero__[^"]*"[\s\S]*?<\/section>/) ||
    rawHtml.match(/<section class="HomeMoBannerHero_banner_hero__[^"]*"[\s\S]*?<\/section>/);
  return match ? match[0] : "";
}

function extractHomeHeroSlides(rawHtml) {
  const slides = [];
  const heroMatch =
    rawHtml.match(/<section class="HomePcBannerHero_banner_hero__[^"]*"[\s\S]*?<\/section>/) ||
    rawHtml.match(/<section class="HomeTaBannerHero_banner_hero__[^"]*"[\s\S]*?<\/section>/);
  const heroHtml = heroMatch ? heroMatch[0] : "";
  const slidePattern =
    /<div class="swiper-slide">[\s\S]*?<a class="(?:HomePcBannerHero_banner_hero_item__|HomeTaBannerHero_banner_hero_item__)[^"]*"[^>]*href="([^"]+)"[^>]*>([\s\S]*?)<\/a><\/div>/g;
  let match;
  while ((match = slidePattern.exec(heroHtml))) {
    const inner = match[2];
    slides.push({
      href: match[1],
      badge: stripHtml(
        (
          inner.match(/<span class="(?:HomePcBannerHero_banner_hero_badge__|HomeTaBannerHero_banner_hero_badge__)[^"]*"[^>]*>([\s\S]*?)<\/span>/) ||
          [])[1] || ""
      ),
      headline: stripHtml(
        (
          inner.match(/<strong class="(?:HomePcBannerHero_banner_hero_headline__|HomeTaBannerHero_banner_hero_headline__)[^"]*"[^>]*>([\s\S]*?)<\/strong>/) ||
          [])[1] || ""
      ),
      description: stripHtml(
        (
          inner.match(/<p class="(?:HomePcBannerHero_banner_hero_description__|HomeTaBannerHero_banner_hero_description__)[^"]*"[^>]*>([\s\S]*?)<\/p>/) ||
          [])[1] || ""
      ),
      imageSrc: ((inner.match(/<img[^>]*src="([^"]+)"/) || [])[1] || ""),
    });
  }
  return slides;
}

